// VHYX — mapeia achievement id → badge fatiado (icons/badges/<name>.webp).
// 8 badges visuais cobrem 19 das 20 conquistas. Tema do badge casa com o
// tipo de progressão (streak → consistency, treino → cardio, etc).
const ACHIEVEMENT_BADGE = {
  first_log:    'stamina',
  streak3:      'consistency',
  streak7:      'consistency',
  streak30:     'energy',
  protein5:     'hydration',
  protein30:    'hydration',
  workout10:    'cardio',
  workout50:    'cardio',
  sleep7d:      'recovery',
  reading7:     'energy',
  reading_book: 'energy',
  steps_10k:    'cardio',
  reach_gold:   'victory',
  reach_plat:   'victory',
  reach_dia:    'victory',
  reach_master: 'victory',
  reach_chall:  'victory',
  quest_50:     'return',
  pr:           'return',
  // photo_pair fica só com emoji
};

// Helpers usados por ACHIEVEMENTS (definidos antes para evitar TDZ no array).
function getMaxLogStreak(s) {
  if (!s.dailyLogs.length) return 0;
  const days = new Set(s.dailyLogs.map(l => l.date));
  let best = 0;
  for (const d of days) {
    let cur = 1;
    const dt = new Date(d);
    while (true) {
      dt.setDate(dt.getDate() - 1);
      if (days.has(isoDate(dt))) cur++; else break;
    }
    if (cur > best) best = cur;
  }
  return best;
}
function hasPR(s) {
  // Existe algum exercício onde a sessão mais nova tem peso > sessão anterior
  const byEx = new Map();
  for (const w of s.workouts) {
    for (const ex of w.exercises) {
      const top = Math.max(...ex.sets.map(set => +set.weight || 0));
      if (!byEx.has(ex.name)) byEx.set(ex.name, []);
      byEx.get(ex.name).push({ date: w.date, top });
    }
  }
  for (const [, sessions] of byEx) {
    sessions.sort((a, b) => a.date < b.date ? 1 : -1);
    if (sessions.length >= 2 && sessions[0].top > sessions[1].top) return true;
  }
  return false;
}

