function loadState() {
  try {
    const acc = currentAccount();
    const key = stateKey(acc?.id);
    let raw = localStorage.getItem(key);
    // Compat: se a conta foi recém-criada e não tem state, mas existe
    // state no key legado (quest.state.v1), promove pra essa conta.
    if (!raw && acc) {
      const legacy = localStorage.getItem(STORAGE_KEY);
      if (legacy) raw = legacy;
    }
    if (!raw) return null;
    const s = JSON.parse(raw);
    migrateState(s);
    return s;
  } catch (e) {
    console.error('Falha lendo localStorage:', e);
    return null;
  }
}

/** Garante que campos novos apareçam mesmo em estados antigos.
 *  Idempotente — chame quantas vezes quiser sem efeito colateral. */
function migrateState(s) {
  if (!s) return;
  // Tema fixo no kpop_anime (MK + K-pop). Themes alternativos removidos da UI.
  s.user = s.user || {};
  s.user.theme = 'kpop_anime';

  // Limpa currentNutriDate persistido (bug v1.12 — agora é module-level só).
  // Se usuário tinha ficado preso vendo um dia passado, a próxima sessão
  // volta pra hoje automaticamente.
  if ('currentNutriDate' in s.user) delete s.user.currentNutriDate;

  // Marca quests específicas de K-pop no pool já salvo (idempotente).
  // Tudo com tag 'k-pop' ou id começando 't1_kp' (do tema kpop_anime) vira kpopOnly.
  const KPOP_QUEST_IDS = new Set(['q26', 'q32', 'q33', 'q34', 'q35', 'q36']);
  if (s.quests?.pool) {
    s.quests.pool.forEach((q) => {
      if (KPOP_QUEST_IDS.has(q.id)) q.kpopOnly = true;
      if (q.tag === 'k-pop') q.kpopOnly = true;
      if (typeof q.id === 'string' && q.id.startsWith('t1_kp')) q.kpopOnly = true;
      if (q.ko && /[가-힣]/.test(q.ko)) q.kpopOnly = true; // qualquer ko com hangul → kpop
    });

    // Merge: insere quests built-in novas (DEFAULT_QUEST_POOL) que ainda não
    // estão no pool do usuário, preservando todas as adicionadas por ele.
    const existingIds = new Set(s.quests.pool.map((q) => q.id));
    for (const builtIn of DEFAULT_QUEST_POOL) {
      if (!existingIds.has(builtIn.id)) {
        s.quests.pool.push({ ...builtIn });
      }
    }
  }

  // Garante que weekly quest atual tenha target. Procura no pool default +
  // pools temáticos pelo id antes de cair no default 1.
  function findTargetById(id) {
    const inDefault = DEFAULT_WEEKLY_POOL.find((q) => q.id === id);
    if (inDefault?.target != null) return inDefault.target;
    for (const t of Object.values(THEMES)) {
      const m = (t.weeklyQuests || []).find((q) => q.id === id);
      if (m?.target != null) return m.target;
    }
    return 1;
  }
  // Sempre alinha o target ao definido no pool (migração agressiva — sobrescreve
  // valores defaults de 1 atribuídos por migrações antigas).
  if (s.quests?.weeklyCurrent?.item) {
    const real = findTargetById(s.quests.weeklyCurrent.item.id);
    s.quests.weeklyCurrent.item.target = real;
  }
  if (Array.isArray(s.quests?.weeklyPool)) {
    s.quests.weeklyPool.forEach((q) => {
      if (q) q.target = findTargetById(q.id);
    });
  }

  s.rewards = s.rewards || { available: [], unlocked: [], redeemed: [] };
  s.rewards.available = s.rewards.available || [];
  const newRewards = [
    '1 partida de LoL (ranqueada)',
    '2 partidas de LoL (normal/aram)',
    '1 episódio de anime',
    'Maratona 3 eps do anime atual',
  ];
  // Compatibilidade: aceita strings legadas e objetos novos {id, text, daily}
  const existingTexts = new Set(
    s.rewards.available.map((r) => typeof r === 'string' ? r : r.text)
  );
  for (const r of newRewards) {
    if (!existingTexts.has(r)) s.rewards.available.push(r);
  }

  // Migração de rank keys antigos (sem divisão) → novos com sub-tiers.
  // Old: 'iron' → New: 'iron4' (ou recalcula pelo rankXP atual, mais robusto).
  s.user = s.user || {};
  const OLD_RANK_TO_NEW = {
    iron: 'iron4', bronze: 'bronze4', silver: 'silver4', gold: 'gold4',
    platinum: 'plat4', emerald: 'emerald4', diamond: 'dia4', master: 'master4',
    grandmaster: 'gm', challenger: 'challenger',
  };
  if (s.user.currentRank && OLD_RANK_TO_NEW[s.user.currentRank]) {
    s.user.currentRank = OLD_RANK_TO_NEW[s.user.currentRank];
  }
  // Se o rank atual não existe mais, recalcula pelo rankXP
  if (s.user.currentRank && !RANKS.find(r => r.key === s.user.currentRank)) {
    s.user.currentRank = rankFromXP(s.user.rankXP || 0).key;
  }
  // Migra rankHistory também
  if (Array.isArray(s.rankHistory)) {
    s.rankHistory = s.rankHistory.map(h => ({
      ...h,
      rank: OLD_RANK_TO_NEW[h.rank] || h.rank,
    }));
  }

  // Migração de keys antigas de GOALS → novas (após rework por grupo muscular).
  if (Array.isArray(s.user.activeGoals)) {
    const goalKeyMap = {
      // Keys antigas (versões 1 e 2) → novas keys por grupo muscular
      'cage_arms':    'definicao',
      'jeno_abs':     'abdomen',
      'liu_pecs':     'peitoral',
      'subzero_back': 'dorsal',
      'wonho_arms':   'bracos',
      'jaypark_lean': 'calistenia',
      'johnny':       'bracos',
      'leejeno':      'abdomen',
      'kano':         'forca',
      'liukang':      'peitoral',
      'subzero':      'dorsal',
      'raiden':       'ombros',
      'scorpion':     'cardio',
      'cage':         'definicao',
      // sem foto correspondente: kitana_legs, karina_waist, lisa_thighs, stage_ready → removidos
    };
    const validKeys = new Set(['bracos','abdomen','calistenia','forca','peitoral','dorsal','ombros','cardio','definicao']);
    s.user.activeGoals = s.user.activeGoals
      .map((k) => goalKeyMap[k] || k)
      .filter((k) => validKeys.has(k));
    s.user.activeGoals = Array.from(new Set(s.user.activeGoals));
  }

  // Roster reduzido (v1.79+) — só 2 lutadores: AXEL KAEL e KAI RYUEN.
  // Quem tinha yeonjun/cagemorgan/sanji/joehigashi (ou qualquer outro removido)
  // como ativo, limpa pra forçar reseleção na próxima abertura.
  const VALID_CHARS = new Set(['axelkael', 'kairyuen', 'luansantos']);
  if (s.user.activeCharacter && !VALID_CHARS.has(s.user.activeCharacter)) {
    delete s.user.activeCharacter;
  }

  // Spotify (v1.55+) — garante o objeto e seus campos pra states antigos
  s.user.spotify = s.user.spotify || {};
  s.user.spotify.clientId    = s.user.spotify.clientId    || '';
  s.user.spotify.accessToken = s.user.spotify.accessToken || '';
  s.user.spotify.refreshToken = s.user.spotify.refreshToken || '';
  s.user.spotify.expiresAt   = s.user.spotify.expiresAt   || 0;
  s.user.spotify.scope       = s.user.spotify.scope       || '';

  // Claude/Anthropic (v1.69+) — garante o objeto. Default model = haiku 4.5 (barato).
  s.user.anthropic = s.user.anthropic || {};
  s.user.anthropic.apiKey = s.user.anthropic.apiKey || '';
  s.user.anthropic.model  = s.user.anthropic.model  || 'claude-haiku-4-5-20251001';

  // Perfil comportamental (v1.70+) — base pra análise funcional aplicada à
  // estrutura. Garante o objeto e seus campos pra states antigos.
  s.user.profile = s.user.profile || {};
  if (!Array.isArray(s.user.profile.conditions)) s.user.profile.conditions = [];
  s.user.profile.goal = s.user.profile.goal || 'definicao_abs';
  s.user.profile.engagement = s.user.profile.engagement || { gym: 'medio', diet: 'medio' };
  s.user.profile.engagement.gym = s.user.profile.engagement.gym || 'medio';
  s.user.profile.engagement.diet = s.user.profile.engagement.diet || 'medio';
  s.user.profile.notes = s.user.profile.notes || '';
  if (typeof s.user.profile.lowSensory !== 'boolean') s.user.profile.lowSensory = false;
  s.user.profile.description = s.user.profile.description || '';
  if (!Array.isArray(s.user.profile.customQuests)) s.user.profile.customQuests = [];
  if (!Array.isArray(s.user.personalRewards)) s.user.personalRewards = [];

  // Plano semanal (v1.76+) — agenda Smartfit-style por dia da semana
  s.user.weeklyPlan = s.user.weeklyPlan || {
    dom: 'descanso', seg: 'A · Peito + Tríceps + Abs',
    ter: 'B · Costas + Ombros + Bíceps + Abs', qua: 'Caminhada',
    qui: 'C · Pernas completo + Abs', sex: 'Upper completo', sab: 'descanso',
  };
  ['dom','seg','ter','qua','qui','sex','sab'].forEach(d => {
    if (!s.user.weeklyPlan[d]) s.user.weeklyPlan[d] = 'descanso';
  });

  // PRÉ-PREENCHE com o perfil declarado pelo user no chat (apenas se ainda
  // não tiver dado nenhuma condition — não sobrescreve escolha consciente).
  if (s.user.profile.conditions.length === 0) {
    s.user.profile.conditions = ['tdah', 'tag', 'autismo_possivel'];
    s.user.profile.goal = 'definicao_abs';
    s.user.profile.engagement = { gym: 'alto', diet: 'baixo' };
  }

  // Livros (v1.57+) — categoria 'literatura' (default) ou 'artigo', + id estável.
  // currentLiteraturaBookId aponta pro livro sorteado em curso (null = precisa sortear).
  if (Array.isArray(s.books)) {
    s.books.forEach((b) => {
      if (!b.id) b.id = 'b_' + Math.random().toString(36).slice(2, 9) + Date.now().toString(36).slice(-4);
      if (!b.category) b.category = 'literatura';
    });
  }
  if (s.user.currentLiteraturaBookId === undefined) s.user.currentLiteraturaBookId = null;

  // Day rollover (v1.57+) — preenche dias passados que ficaram sem log com
  // um entry autoClosed=true (neutro: xp=0, não conta sleep/training/etc).
  // Só preenche entre o primeiro log do usuário e ontem (não inventa histórico).
  if (Array.isArray(s.dailyLogs) && s.dailyLogs.length) {
    const today = todayISO();
    const logged = new Set(s.dailyLogs.map(l => l.date));
    const realLogs = s.dailyLogs.filter(l => !l.autoClosed);
    if (realLogs.length) {
      const earliest = realLogs.reduce((m, l) => l.date < m ? l.date : m, realLogs[0].date);
      const start = new Date(earliest + 'T00:00:00');
      const end = new Date(today + 'T00:00:00');
      let added = 0;
      for (let d = new Date(start); d < end; d.setDate(d.getDate() + 1)) {
        const iso = isoDate(d);
        if (!logged.has(iso)) {
          s.dailyLogs.push({ date: iso, autoClosed: true, xp: 0 });
          added++;
        }
      }
      if (added) s.dailyLogs.sort((a, b) => a.date.localeCompare(b.date));
    }
  }
}

function saveState() {
  try {
    const acc = currentAccount();
    localStorage.setItem(stateKey(acc?.id), JSON.stringify(state));
  } catch (e) {
    console.error('Falha gravando localStorage:', e);
    toast('⚠️ Sem espaço para salvar localmente');
  }
  // Espelha pra Firestore (debounced — não bloqueia UI)
  if (cloudReady() && window.QuestCloud.auth.currentUser) {
    scheduleCloudSave();
    // Atualiza leaderboard global de leitura
    syncReadingLeaderboard().catch(() => {});
  }
}

/** Popula dados de exemplo dos últimos 14 dias para tela "preenchida". */
function seedSampleData() {
  const today = new Date();
  const types = ['Upper B', 'Push', 'Caminhada', 'Core/Abs', 'Braços (bíceps + tríceps)'];
  // Inclui hoje (i=0) para o estado inicial não ficar "Ferro 0 XP".
  for (let i = 13; i >= 0; i--) {
    const d = new Date(today); d.setDate(d.getDate() - i);
    const iso = isoDate(d);
    const trained = Math.random() > 0.25;
    const proteinG = trained ? 110 + Math.round(Math.random() * 55) : 100 + Math.round(Math.random() * 40);
    const sleepH = +(6.4 + Math.random() * 2.2).toFixed(1);
    const reading = Math.random() > 0.4 ? Math.round(10 + Math.random() * 15) : 0;
    const steps = Math.round(4000 + Math.random() * 9000);
    const buffs = Math.random() > 0.6 ? ['sono'] : (Math.random() > 0.7 ? ['tdah'] : []);
    const log = {
      date: iso,
      training: trained ? { type: types[i % types.length], done: true } : { type: 'descanso', done: false },
      protein: { grams: proteinG, hit: proteinG >= getProteinGoal() },
      sleep: { hours: sleepH },
      reading: { minutes: reading },
      steps,
      buffs,
      notes: '',
    };
    log.xp = computeDayXP(log);
    state.dailyLogs.push(log);
    if (trained) {
      const type = log.training.type;
      const ex = (EXERCISE_LIBRARY[type] || []).slice(0, 4).map((e) => ({
        name: e.name,
        sets: Array.from({ length: 3 }, () => ({
          reps: 6 + Math.floor(Math.random() * 6),
          weight: 20 + Math.floor(Math.random() * 40),
          technique: Math.random() > 0.85 ? 'rest-pause' : '',
        })),
      }));
      state.workouts.push({ date: iso, type, exercises: ex });
    }
  }
  // Medidas semanais
  for (let w = 4; w >= 1; w--) {
    const d = new Date(today); d.setDate(d.getDate() - w * 7);
    state.bodyMeasurements.push({
      date: isoDate(d),
      weight: +(78.5 - w * 0.4 + (Math.random() - 0.5) * 0.6).toFixed(1),
      waist:  +(86 - w * 0.3).toFixed(1),
      chest:  +(101 + w * 0.1).toFixed(1),
      arm:    +(35.5 + w * 0.05).toFixed(1),
    });
  }
  // Livro em andamento
  state.books.push({ title: '코리아: 일상 단어', totalPages: 220, currentPage: 84 });
  state.books.push({ title: 'Atomic Habits', totalPages: 300, currentPage: 156 });

  // XP total acumulado vai direto pro rankXP (mexe no rank)
  const totalEarned = state.dailyLogs.reduce((s, l) => s + (l.xp || 0), 0);
  state.user.totalXP = totalEarned;
  state.user.rankXP = totalEarned;
  state.user.currentRank = rankFromXP(state.user.rankXP).key;
}

// ===== 3. UTILS ==============================================

function isoDate(d = new Date()) {
  // Usa data LOCAL, não UTC. toISOString() volta UTC e pode pular 1 dia
  // dependendo do fuso (em UTC+X de manhã vira dia anterior; em UTC-X de
  // noite vira dia seguinte). Sempre queremos a data no fuso do usuário.
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
}
function todayISO() { return isoDate(new Date()); }

function startOfWeek(date = new Date()) {
  const d = new Date(date);
  const day = d.getDay(); // 0=domingo
  d.setHours(0, 0, 0, 0);
  d.setDate(d.getDate() - day);
  return d;
}

function weeklyXP() {
  const start = startOfWeek();
  return state.dailyLogs
    .filter((l) => new Date(l.date) >= start)
    .reduce((s, l) => s + (l.xp || 0), 0);
}

function rankFromXP(xp) {
  let r = RANKS[0];
  for (const x of RANKS) if (xp >= x.threshold) r = x;
  return r;
}

/** Aplica ganho/perda de XP — atualiza totalXP e rankXP, detecta promoção e
 *  dispara verificação de achievements. Se houver streak ativo, aplica multiplier. */
function gainXP(amount, opts = {}) {
  const before = rankFromXP(state.user.rankXP);
  const mult = (amount > 0 && !opts.noMult) ? comboMultiplier() : 1;
  const finalAmt = Math.round(amount * mult);
  state.user.totalXP = (state.user.totalXP || 0) + finalAmt;
  state.user.rankXP  = Math.max(0, (state.user.rankXP || 0) + finalAmt);
  const after = rankFromXP(state.user.rankXP);
  state.user.currentRank = after.key;

  // Distribui aos atributos se contexto fornecido
  if (opts.attr && finalAmt > 0) addAttributeXP(opts.attr, Math.max(1, Math.round(finalAmt * 0.5)));

  // Achievements e skin checks
  setTimeout(() => checkAchievements(), 50);

  if (before.key !== after.key) {
    const promoted = RANKS.indexOf(after) > RANKS.indexOf(before);
    return { changed: true, from: before, to: after, promoted, finalAmt, mult };
  }
  return { changed: false, finalAmt, mult };
}

/** Multiplicador de XP por sequência: 3 dias = 1.1x, 7 = 1.2x, 14 = 1.3x, 30 = 1.5x. */
function comboMultiplier() {
  const s = streaks();
  const best = Math.max(s.treino, s.sono, s.proteina, s.leitura);
  if (best >= 30) return 1.5;
  if (best >= 14) return 1.3;
  if (best >= 7)  return 1.2;
  if (best >= 3)  return 1.1;
  return 1;
}

function addAttributeXP(key, amount) {
  if (!state.user.attributes) state.user.attributes = { forca: 0, resistencia: 0, sabedoria: 0, disciplina: 0, vitalidade: 0 };
  state.user.attributes[key] = (state.user.attributes[key] || 0) + amount;
}

// ===== Atributos estilo Tibia — progressão lenta e exponencial =====
// Cada nível custa ATTR_BASE_COST * ATTR_GROWTH^(level-1) pontos. Crescimento
// 1.08 → nível 30 ≈ 113 XP, nível 50 ≈ 573 XP, nível 70 ≈ 2330 XP, nível
// 100 ≈ 13.7k XP. Combina com adds pequenos por ação pra dar sensação de
// grind realista. Cap de exibição em 200 (matemático ilimitado).
const ATTR_BASE_COST = 1;
const ATTR_GROWTH    = 1.08;

/** Custo absoluto pra ir do nível L-1 pro L (1-indexed: nível 1 = 1 XP). */
function attrCostForLevel(L) {
  return ATTR_BASE_COST * Math.pow(ATTR_GROWTH, L - 1);
}

/** XP total acumulado necessário pra atingir o nível L. */
function attrTotalXPForLevel(L) {
  // Soma da PG: a * (r^L - 1) / (r - 1)
  if (L <= 0) return 0;
  return ATTR_BASE_COST * (Math.pow(ATTR_GROWTH, L) - 1) / (ATTR_GROWTH - 1);
}

/** Retorna { level, intoLevel, nextCost, pctToNext } a partir do XP bruto. */
function attrInfo(xp) {
  xp = Math.max(0, xp || 0);
  let level = 0;
  let total = 0;
  // Loop curto — convergência rápida mesmo pra XP altos
  while (total + attrCostForLevel(level + 1) <= xp && level < 200) {
    total += attrCostForLevel(level + 1);
    level++;
  }
  const nextCost = attrCostForLevel(level + 1);
  const intoLevel = xp - total;
  const pctToNext = Math.min(100, (intoLevel / nextCost) * 100);
  return { level, intoLevel, nextCost, pctToNext };
}

