/** View completa da aba Calistenia — roadmap interativo com nível atual,
 *  movimentos detalhados e dicas de progressão. */
function viewCalistenia() {
  const userLevel = state.user.calisteniaLevel ?? 0;
  const currentLv = CALISTENIA_ROADMAP[Math.min(userLevel, CALISTENIA_ROADMAP.length - 1)];
  const nextLv = CALISTENIA_ROADMAP[Math.min(userLevel + 1, CALISTENIA_ROADMAP.length - 1)];
  const movCount = CALISTENIA_ROADMAP.reduce((s, lv) => s + lv.movements.length, 0);

  return `
  <header class="pt-7 pb-3 px-5 kombat-hero">
    <div class="kombat-tagline text-xs">CALISTHENICS PATH</div>
    <h1 class="text-2xl font-extrabold mt-1">Calistenia</h1>
    <p class="text-sm text-ink/55 dark:text-paper/55">Do iniciante absoluto ao mestre. ${movCount} movimentos com técnica completa.</p>
  </header>

  <!-- Card do nível atual -->
  <section class="px-4 mt-2">
    <div class="q-card p-4 relative" style="border-left:4px solid ${currentLv.color}">
      <div class="flex items-center justify-between gap-2 mb-2">
        <div>
          <div class="text-[10px] uppercase tracking-widest font-semibold" style="color:${currentLv.color}">Seu nível atual</div>
          <div class="font-extrabold text-lg mt-0.5">Nível ${currentLv.level} · ${currentLv.name}</div>
        </div>
        <span class="text-[10px] text-ink/45 dark:text-paper/45">${currentLv.weeks}</span>
      </div>
      <div class="text-xs text-ink/65 dark:text-paper/65 leading-snug">${currentLv.desc}</div>
      <div class="mt-3 p-2.5 rounded text-[11px]" style="background:rgba(168,230,207,0.12); border-left:2px solid #3FBF7F">
        <b>🎯 Critério pra avançar:</b> ${currentLv.criteria}
      </div>
      ${userLevel < CALISTENIA_ROADMAP.length - 1 ? `
        <div class="mt-2 p-2.5 rounded text-[11px]" style="background:rgba(255,216,168,0.12); border-left:2px solid #FFD8A8">
          <b>➡️ Próximo:</b> Nível ${nextLv.level} · ${nextLv.name}
        </div>` : ''}
      <div class="flex items-center gap-1 mt-3 flex-wrap">
        <span class="text-[10px] text-ink/55 dark:text-paper/55">Marcar nível:</span>
        ${CALISTENIA_ROADMAP.map((lv) => `
          <button class="calist-level-btn pill text-[10px] ${lv.level === userLevel ? 'is-mint font-bold' : ''}" data-level="${lv.level}">
            ${lv.level}
          </button>
        `).join('')}
      </div>
    </div>
  </section>

  <!-- Todos os níveis -->
  <section class="px-4 mt-3 mb-2">
    <h2 class="font-extrabold text-base mb-2">Roadmap completo</h2>
    <div class="space-y-2">
      ${CALISTENIA_ROADMAP.map((lv) => {
        const isCurrent = lv.level === userLevel;
        return `
        <details class="q-card overflow-hidden" ${isCurrent ? 'open' : ''} style="border-left:4px solid ${lv.color}">
          <summary class="cursor-pointer list-none p-3">
            <div class="flex items-center justify-between gap-2">
              <div class="min-w-0 flex-1">
                <div class="text-[10px] uppercase tracking-widest font-semibold" style="color:${lv.color}">
                  Nível ${lv.level} · ${lv.weeks}${isCurrent ? ' · <span class="text-mint">você está aqui</span>' : ''}
                </div>
                <div class="font-extrabold text-base mt-0.5">${lv.name}</div>
              </div>
              <span class="text-[10px] text-ink/45 dark:text-paper/45">▼</span>
            </div>
            <div class="text-xs text-ink/65 dark:text-paper/65 leading-snug mt-2">${lv.desc}</div>
          </summary>
          <div class="px-3 pb-3">
            <div class="p-2 mt-1 rounded text-[11px]" style="background:rgba(168,230,207,0.12); border-left:2px solid #3FBF7F">
              <b>🎯 Critério pra avançar:</b> ${lv.criteria}
            </div>
            <div class="mt-3 space-y-2">
              ${lv.movements.map((m) => `
                <details class="q-card p-2.5">
                  <summary class="cursor-pointer list-none">
                    <div class="flex items-center justify-between gap-2">
                      <div class="min-w-0 flex-1">
                        <div class="font-bold text-sm truncate">${m.name}</div>
                        <div class="text-[10px] text-ink/55 dark:text-paper/55">${m.muscles}</div>
                      </div>
                      <span class="pill is-mint text-[10px] whitespace-nowrap">${m.target}</span>
                    </div>
                  </summary>
                  <div class="mt-2 text-[11px] space-y-1.5 leading-snug">
                    <div><b class="text-lavender">Técnica:</b> ${m.technique}</div>
                    ${m.mistakes ? `<div><b class="text-pink">Erros comuns:</b> ${m.mistakes}</div>` : ''}
                    ${m.next ? `<div><b class="text-mint">Próximo passo:</b> ${m.next}</div>` : ''}
                  </div>
                </details>
              `).join('')}
            </div>
          </div>
        </details>`;
      }).join('')}
    </div>
    <p class="text-[10px] text-ink/45 dark:text-paper/45 mt-3 italic">
      ⚠️ Não pule níveis — forçar progressões avançadas sem base = lesão garantida.
      Frequência ideal: 3-4×/sem, descanso de 48h em grupos muito treinados.
    </p>
  </section>
  `;
}

// ===== Import de treino externo (Polar Flow / Garmin / Strava / Apple Watch) =====
// Aceita 2 caminhos:
// 1. Upload de arquivo TCX/GPX (formato padrão exportado pelos apps).
// 2. Paste do texto-resumo da atividade (formato livre — extrai com regex).

/** Parser TCX (XML). Extrai duração, kcal, FC média, esporte. */
function parseTcxFile(xmlText) {
  try {
    const parser = new DOMParser();
    const doc = parser.parseFromString(xmlText, 'text/xml');
    const activity = doc.querySelector('Activity');
    if (!activity) return null;
    const sport = activity.getAttribute('Sport') || 'Outro';
    let totalSec = 0;
    let totalKcal = 0;
    let totalDistM = 0;
    let hrSamples = [];
    activity.querySelectorAll('Lap').forEach((lap) => {
      const t = +(lap.getAttribute('TotalTimeSeconds') || lap.querySelector('TotalTimeSeconds')?.textContent || 0);
      const kcal = +(lap.querySelector('Calories')?.textContent || 0);
      const dist = +(lap.querySelector('DistanceMeters')?.textContent || 0);
      totalSec += t;
      totalKcal += kcal;
      totalDistM += dist;
      lap.querySelectorAll('HeartRateBpm > Value').forEach((v) => {
        const n = +v.textContent;
        if (n > 0) hrSamples.push(n);
      });
    });
    const avgHr = hrSamples.length ? Math.round(hrSamples.reduce((a, b) => a + b, 0) / hrSamples.length) : 0;
    const startTime = activity.querySelector('Id')?.textContent || '';
    const date = startTime ? startTime.slice(0, 10) : todayISO();
    return {
      sport, durationMin: Math.round(totalSec / 60), kcal: Math.round(totalKcal),
      distanceKm: +(totalDistM / 1000).toFixed(2), avgHr, date,
    };
  } catch (e) {
    console.warn('TCX parse failed:', e);
    return null;
  }
}

/** Parser GPX (mais simples — só GPS + tempo). */
function parseGpxFile(xmlText) {
  try {
    const parser = new DOMParser();
    const doc = parser.parseFromString(xmlText, 'text/xml');
    const pts = doc.querySelectorAll('trkpt');
    if (!pts.length) return null;
    const firstT = pts[0].querySelector('time')?.textContent;
    const lastT  = pts[pts.length - 1].querySelector('time')?.textContent;
    let totalSec = 0;
    if (firstT && lastT) totalSec = (new Date(lastT) - new Date(firstT)) / 1000;
    // Distância via haversine entre pontos consecutivos
    function hav(p1, p2) {
      const toRad = (d) => d * Math.PI / 180;
      const lat1 = toRad(+p1.getAttribute('lat')), lat2 = toRad(+p2.getAttribute('lat'));
      const dLat = lat2 - lat1;
      const dLon = toRad(+p2.getAttribute('lon') - +p1.getAttribute('lon'));
      const a = Math.sin(dLat/2)**2 + Math.cos(lat1)*Math.cos(lat2)*Math.sin(dLon/2)**2;
      return 6371000 * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
    }
    let totalM = 0;
    for (let i = 1; i < pts.length; i++) totalM += hav(pts[i-1], pts[i]);
    const name = doc.querySelector('trk > name')?.textContent || 'GPX import';
    return {
      sport: /run|corrida/i.test(name) ? 'Running' : /bike|cycl/i.test(name) ? 'Biking' : 'Walking',
      durationMin: Math.round(totalSec / 60), kcal: 0,
      distanceKm: +(totalM / 1000).toFixed(2), avgHr: 0,
      date: firstT ? firstT.slice(0, 10) : todayISO(),
    };
  } catch (e) {
    console.warn('GPX parse failed:', e);
    return null;
  }
}

/** Parser de texto-resumo (formato livre). Extrai duração, distância, FC, kcal. */
function parsePastedSummary(text) {
  const out = { sport: '', durationMin: 0, distanceKm: 0, avgHr: 0, kcal: 0, date: todayISO() };
  // Duração: "31:25", "1h 12min", "45 min", "0:31:25"
  const hms = text.match(/(\d+):(\d{2}):(\d{2})/);
  const ms  = text.match(/(\d{1,2}):(\d{2})(?!\d)/);
  const hmin = text.match(/(\d+)\s*h\s*(\d+)\s*min/i);
  const minOnly = text.match(/(\d+)\s*min(?:utos)?/i);
  if (hms) out.durationMin = +hms[1] * 60 + +hms[2] + Math.round(+hms[3] / 60);
  else if (hmin) out.durationMin = +hmin[1] * 60 + +hmin[2];
  else if (ms) out.durationMin = +ms[1] + Math.round(+ms[2] / 60);
  else if (minOnly) out.durationMin = +minOnly[1];
  // Distância: "5.2 km", "10,3km", "5200 m"
  const km = text.match(/(\d+[\.,]\d+|\d+)\s*km/i);
  if (km) out.distanceKm = +km[1].replace(',', '.');
  // FC: "FC 156", "156 bpm", "HR 156"
  const hr = text.match(/(?:fc|hr|bpm.*?média|fcmédia)[:\s]*(\d{2,3})|(\d{2,3})\s*bpm/i);
  if (hr) out.avgHr = +(hr[1] || hr[2]);
  // Calorias: "412 kcal", "300 cal"
  const kcal = text.match(/(\d+)\s*k?cal/i);
  if (kcal) out.kcal = +kcal[1];
  // Esporte por keywords
  const lower = text.toLowerCase();
  if (/corrida|corri|run|trote/.test(lower)) out.sport = 'Corrida';
  else if (/bike|cycl|pedalei|ciclis/.test(lower)) out.sport = 'Bike';
  else if (/caminh|walk|andar/.test(lower)) out.sport = 'Caminhada';
  else if (/natação|natacao|swim|piscina/.test(lower)) out.sport = 'Natação';
  else if (/dança|dance|coreo/.test(lower)) out.sport = 'Dança';
  else out.sport = 'Cardio';
  return out;
}

/** Mapeia esporte do TCX → tipo de treino do QUEST. */
function tcxSportToQuestType(sport) {
  const s = (sport || '').toLowerCase();
  if (/run/.test(s) || /corrida/.test(s)) return 'Caminhada';
  if (/bik/.test(s) || /cycl/.test(s))    return 'Caminhada';
  if (/walk/.test(s) || /walking/.test(s) || /caminh/.test(s)) return 'Caminhada';
  if (/swim/.test(s) || /natac/.test(s) || /natação/.test(s))  return 'Caminhada';
  return 'Caminhada';
}

