/** Modal de LORE completa do operador — história, origem dos poderes,
 *  aliados, inimigos. Acessível via botão na tela expandida do SELECT
 *  OPERATOR e via botão na ficha do Elo Card da home. */
function modalCharacterLore(charId) {
  const ch = CHARACTERS.find((c) => c.id === charId);
  if (!ch || !ch.unlocked) return;
  const accent = ch.accent || 'var(--vhyx-cyan, #6EEEFF)';
  const allyById = (id) => CHARACTERS.find((c) => c.id === id);
  const allies = (ch.allies || []).map((a) => {
    const al = allyById(a.id);
    if (!al) return '';
    return `
      <div class="vhyx-lore-relation vhyx-lore-ally">
        <img src="${al.img}" alt="${al.name}" loading="lazy" />
        <div>
          <div class="vhyx-lore-relation-name" style="color:${al.accent}">${al.name}</div>
          <div class="vhyx-lore-relation-desc">${a.relation}</div>
        </div>
      </div>`;
  }).join('');
  const enemies = (ch.enemies || []).map((e) => `
    <div class="vhyx-lore-relation vhyx-lore-enemy">
      <div class="vhyx-lore-enemy-skull">⚠</div>
      <div>
        <div class="vhyx-lore-relation-name vhyx-lore-enemy-name">${e.name}</div>
        <div class="vhyx-lore-relation-desc">${e.desc}</div>
      </div>
    </div>`).join('');

  // paragraphs(): aceita histories escritas com \n\n real OU com literal \\n\\n
  // (4 chars: backslash-n-backslash-n). Normaliza tudo pra quebra real antes
  // de splittar.
  const paragraphs = (txt) => (txt || '').replace(/\\n\\n/g, '\n\n').split(/\n\n+/).map(p => `<p>${p}</p>`).join('');
  const faction = (VHYX_WORLD.factions || []).find(f => f.key === ch.faction);
  const universeFactions = (VHYX_WORLD.factions || []).map(f => `
    <div class="vhyx-lore-faction vhyx-lore-faction-${f.side}">
      <div class="vhyx-lore-faction-name">${f.name}</div>
      <div class="vhyx-lore-faction-tagline">${f.tagline}</div>
      <div class="vhyx-lore-faction-desc">${f.desc}</div>
    </div>`).join('');

  openModal(`
    <div class="vhyx-lore-hero" style="background-image: url('${ch.img}')">
      <button class="workout-hero-btn workout-hero-btn-right modal-close" aria-label="Fechar">✕</button>
      <div class="vhyx-lore-hero-overlay">
        <div class="vhyx-lore-eyebrow" style="color:${accent}">▸ CODEX DO OPERADOR · ${ch.slot}</div>
        <h2 class="vhyx-lore-title">${ch.name}</h2>
        <div class="vhyx-lore-subtitle">${ch.title}</div>
        ${faction ? `<div class="vhyx-lore-faction-pill" style="border-color:${accent}; color:${accent}">${faction.name}</div>` : ''}
        ${ch.mantra ? `<div class="vhyx-lore-mantra">"${ch.mantra}"</div>` : ''}
      </div>
    </div>
    <div class="vhyx-lore-body">

      ${ch.bounty ? `
      <div class="vhyx-lore-bounty">
        <span class="vhyx-lore-bounty-label">⚠ FICHA NF</span>
        <span class="vhyx-lore-bounty-value">${ch.bounty}</span>
      </div>` : ''}

      ${ch.ability ? `
      <section class="vhyx-lore-section">
        <div class="vhyx-lore-section-head" style="border-color:${accent}">
          <span class="vhyx-lore-section-icon">⚡</span>
          <h3>Habilidade · ${ch.ability.name}</h3>
        </div>
        <p>${ch.ability.desc}</p>
        ${ch.ability.cost ? `<p class="vhyx-lore-cost"><b>Custo:</b> ${ch.ability.cost}</p>` : ''}
      </section>` : ''}

      ${ch.awakening ? `
      <section class="vhyx-lore-section">
        <div class="vhyx-lore-section-head" style="border-color:${accent}">
          <span class="vhyx-lore-section-icon">🌀</span>
          <h3>O Despertar · ${ch.awakening.age} anos · ${ch.awakening.year}</h3>
        </div>
        <p>${ch.awakening.event}</p>
      </section>` : ''}

      <section class="vhyx-lore-section">
        <div class="vhyx-lore-section-head" style="border-color:${accent}">
          <span class="vhyx-lore-section-icon">📖</span>
          <h3>História</h3>
        </div>
        ${paragraphs(ch.history || ch.lore || '—')}
      </section>

      ${ch.arc ? `
      <section class="vhyx-lore-section vhyx-lore-arc">
        <div class="vhyx-lore-section-head" style="border-color:${accent}">
          <span class="vhyx-lore-section-icon">🎯</span>
          <h3>Arco Atual</h3>
        </div>
        ${paragraphs(ch.arc)}
      </section>` : ''}

      ${allies ? `
      <section class="vhyx-lore-section">
        <div class="vhyx-lore-section-head" style="border-color:${accent}">
          <span class="vhyx-lore-section-icon">🤝</span>
          <h3>Aliados</h3>
        </div>
        <div class="vhyx-lore-relations">${allies}</div>
      </section>` : ''}

      ${enemies ? `
      <section class="vhyx-lore-section">
        <div class="vhyx-lore-section-head" style="border-color:#FF6B6B">
          <span class="vhyx-lore-section-icon">⚔</span>
          <h3>Inimigos</h3>
        </div>
        <div class="vhyx-lore-relations">${enemies}</div>
      </section>` : ''}

      <section class="vhyx-lore-section vhyx-lore-universe">
        <div class="vhyx-lore-section-head" style="border-color:var(--vhyx-cyan, #6EEEFF)">
          <span class="vhyx-lore-section-icon">🌐</span>
          <h3>O Universo VHYX · ${VHYX_WORLD.era}</h3>
        </div>
        <div class="vhyx-lore-event">
          <div class="vhyx-lore-event-title">${VHYX_WORLD.origin.title}</div>
          <p>${VHYX_WORLD.origin.body}</p>
        </div>
        <div class="vhyx-lore-factions">${universeFactions}</div>
        <p class="vhyx-lore-protocol-note">${VHYX_WORLD.protocol}</p>
        <button class="cs-lore-btn vhyx-open-universe" data-open-universe style="margin-top:14px">🌐 ABRIR MUNDO VHYX · CRÔNICA COMPLETA</button>
      </section>

      <section class="vhyx-lore-section">
        <div class="vhyx-lore-section-head" style="border-color:${accent}">
          <span class="vhyx-lore-section-icon">⚙</span>
          <h3>Ficha Técnica</h3>
        </div>
        <dl class="vhyx-lore-spec">
          <dt>Origem</dt><dd>${ch.origin || '—'}</dd>
          <dt>Estilo</dt><dd>${ch.style || '—'}</dd>
          <dt>Idade</dt><dd>${ch.age || '—'} anos</dd>
          <dt>Categoria</dt><dd>${ch.slot} · ${faction?.name || '—'}</dd>
        </dl>
      </section>
    </div>
  `);
  // Liga o botão MUNDO VHYX dentro do modal de lore — abre crônica completa
  document.querySelector('[data-open-universe]')?.addEventListener('click', () => {
    closeModal();
    setTimeout(() => modalUniverseVHYX(), 100);
  });
}

function modalAttributeDetail(attrKey) {
  const a = ATTRIBUTES.find((x) => x.key === attrKey);
  if (!a) return;
  const attrs = state.user.attributes || {};
  const xp = attrs[attrKey] || 0;
  const info = attrInfo(xp);
  const tier = attrTierFor(attrKey, info.level);
  const tipsBlock = ATTR_LEVEL_UP_TIPS[attrKey] || { title: 'Dicas', subtitle: '', tips: [] };
  // Últimos eventos do battle log filtrados pelas tags dessa categoria
  const tagsByAttr = {
    forca:       ['treino'],
    resistencia: ['cardio'],
    sabedoria:   ['foco'],
    disciplina:  ['nutri', 'sono'],
    vitalidade:  ['saúde', 'mente', 'k-pop'],
  };
  const myTags = new Set(tagsByAttr[attrKey] || []);
  const log = (state.user.battleLog || []).filter((ev) => {
    const txt = ev.text || '';
    return [...myTags].some((t) => {
      const ti = QUEST_TAG_INFO[t];
      return ti && txt.includes(ti.emoji);
    });
  }).slice(0, 5);

  // Imagem do hero — puxa do operador ativo (Axel/Kai/Luan) via mapping
  // dinâmico. Fallback pros webps fixos de icons/attrs/ se não houver match.
  const activeCh = activeCharacter();
  const heroSrc = getAttrImageFor(attrKey, activeCh?.id);
  openModal(`
    <div class="attr-hero" style="background-image: url('${heroSrc}')">
      <button class="workout-hero-btn workout-hero-btn-right modal-close" aria-label="Fechar">✕</button>
      <div class="workout-hero-overlay">
        <div class="font-display text-[10px] uppercase tracking-[0.3em] text-white/70">atributo · ${a.name}</div>
        <h2 class="font-extrabold text-3xl text-white mt-0.5 drop-shadow-lg">${tier.current}</h2>
        <div class="text-[11px] text-white/80 mt-0.5">nível <b class="text-white">${info.level}</b> · ${a.desc}</div>
      </div>
    </div>

    <div class="p-4 overflow-y-auto space-y-4" style="max-height:50vh">

      <!-- Progresso pro próximo nível + tier -->
      <div class="q-card p-3" style="border-left:3px solid ${a.color}">
        <div class="flex items-baseline justify-between mb-1">
          <div class="text-[10px] uppercase tracking-widest text-ink/55 dark:text-paper/55">Progresso</div>
          <div class="text-[10px] text-ink/55 dark:text-paper/55">${info.intoLevel.toFixed(1)} / ${info.nextCost.toFixed(1)} XP</div>
        </div>
        <div class="xp-track mt-1" style="height:8px"><div class="xp-fill" style="width:${info.pctToNext}%; background:${a.color}"></div></div>
        ${tier.next ? `
          <div class="text-[11px] mt-2 leading-snug">
            Próximo tier: <b style="color:${a.color}">${tier.next}</b> em nível <b>${tier.nextMin}</b>
            <span class="text-ink/55 dark:text-paper/55">(faltam ${tier.nextMin - info.level} níveis)</span>
          </div>` : `
          <div class="text-[11px] mt-2 text-ink/55 dark:text-paper/55">Tier máximo atingido. Você é lenda.</div>`}
      </div>

      <!-- Dicas pra subir -->
      <div>
        <div class="text-[10px] uppercase tracking-widest text-ink/55 dark:text-paper/55 mb-2">⚔ ${tipsBlock.title}</div>
        <p class="text-[11px] text-ink/65 dark:text-paper/65 leading-snug mb-2">${tipsBlock.subtitle}</p>
        <div class="space-y-1.5">
          ${tipsBlock.tips.map((t) => `
            <div class="q-card p-2.5 flex items-start gap-2 text-[12px]">
              <span class="text-base shrink-0">${t.icon}</span>
              <span class="leading-snug text-ink/85 dark:text-paper/85">${t.text}</span>
            </div>
          `).join('')}
        </div>
      </div>

      <!-- Battle log recente desse atributo -->
      ${log.length ? `
        <div>
          <div class="text-[10px] uppercase tracking-widest text-ink/55 dark:text-paper/55 mb-2">⚔ XP recente desse atributo</div>
          <div class="space-y-1">
            ${log.map((ev) => `
              <div class="battle-log-entry ${ev.kind === 'pr' ? 'is-pr' : ev.kind === 'loss' ? 'is-loss' : ''}">
                <span class="text-[9px] text-ink/45 dark:text-paper/45 tabular-nums whitespace-nowrap">${timeAgoShort(new Date(ev.ts))}</span>
                <span class="flex-1 text-ink/80 dark:text-paper/80">${ev.text}</span>
              </div>
            `).join('')}
          </div>
        </div>` : ''}

    </div>
  `, { persistent: true });
}

function modalCutting() {
  // Mostra a IMAGEM ORIGINAL do cutting (a mesma que aparece na thumbnail/
  // banner na aba Corpo). Personagem ativo entra só como eyebrow no overlay.
  const ch = activeCharacter();
  const heroImg = 'icons/body/cutting.webp';
  const heroPos = 'center 40%';
  const eyebrow = ch
    ? `${ch.slot} ${ch.name} · cutting guide`
    : 'cutting guide';
  openModal(`
    <div class="attr-hero" style="background-image:url('${heroImg}'); background-position:${heroPos}">
      <button class="workout-hero-btn workout-hero-btn-right modal-close" aria-label="Fechar guia de cutting">✕</button>
      <div class="workout-hero-overlay">
        <div class="font-display text-[10px] uppercase tracking-[0.3em] text-white/70">${eyebrow}</div>
        <h2 class="font-extrabold text-3xl text-white drop-shadow-lg">Cutting saudável</h2>
        <div class="text-[11px] text-white/80 mt-0.5">Perder gordura preservando músculo</div>
      </div>
    </div>
    <div class="p-4 overflow-y-auto space-y-4" style="max-height:55vh">

      <!-- Princípios -->
      <div>
        <div class="text-[10px] uppercase tracking-widest text-ink/55 dark:text-paper/55 mb-2">⚔ Princípios</div>
        <p class="text-[11px] text-ink/65 dark:text-paper/65 leading-snug mb-2">
          Cutting = déficit calórico controlado. Objetivo: <b>perder gordura sem perder músculo</b>.
          Mire em 0.5-1% do peso/semana. Mais rápido que isso, perde músculo junto.
        </p>
      </div>

      <!-- Calorias -->
      <div>
        <div class="text-[10px] uppercase tracking-widest text-ink/55 dark:text-paper/55 mb-2">📊 Calorias</div>
        <div class="space-y-1.5">
          ${[
            { icon: '🔢', text: 'Déficit de 300-500 kcal/dia (não mais). Calc TDEE em Config → Perfil físico.' },
            { icon: '📉', text: 'Pesar diário, média semanal. Se perdeu >1% peso/sem, sobe 100 kcal.' },
            { icon: '🍽️', text: 'Refeed 1x/sem (dia em manutenção) ajuda saúde mental e leptina.' },
          ].map(t => `
            <div class="q-card p-2.5 flex items-start gap-2 text-[12px]">
              <span class="text-base shrink-0">${t.icon}</span>
              <span class="leading-snug text-ink/85 dark:text-paper/85">${t.text}</span>
            </div>`).join('')}
        </div>
      </div>

      <!-- Macros -->
      <div>
        <div class="text-[10px] uppercase tracking-widest text-ink/55 dark:text-paper/55 mb-2">🥩 Macros</div>
        <div class="space-y-1.5">
          ${[
            { icon: '🥩', text: 'Proteína: 1.8-2.2g/kg de peso. É o que MAIS importa pra preservar músculo.' },
            { icon: '🥑', text: 'Gordura: ~0.8-1g/kg (não corta gordura abaixo de 20% das kcal — afeta hormônios).' },
            { icon: '🍚', text: 'Carbo: o resto. Concentra perto dos treinos pra ter energia.' },
            { icon: '🥦', text: 'Fibras: ≥30g/dia. Saciedade + saúde intestinal.' },
          ].map(t => `
            <div class="q-card p-2.5 flex items-start gap-2 text-[12px]">
              <span class="text-base shrink-0">${t.icon}</span>
              <span class="leading-snug text-ink/85 dark:text-paper/85">${t.text}</span>
            </div>`).join('')}
        </div>
      </div>

      <!-- Treino durante cutting -->
      <div>
        <div class="text-[10px] uppercase tracking-widest text-ink/55 dark:text-paper/55 mb-2">💪 Treino</div>
        <div class="space-y-1.5">
          ${[
            { icon: '🏋️', text: 'MANTÉM as cargas. Reduzir peso = sinal pro corpo "pode soltar músculo".' },
            { icon: '🔁', text: 'Volume igual ou levemente reduzido (10-15% menos series se cansaço bater).' },
            { icon: '🚶', text: 'Cardio: caminhada 7-10k passos/dia. HIIT 1-2x/sem. Não substitui força.' },
            { icon: '⏸️', text: 'Descanso entre séries pode aumentar — energia fica menor com déficit.' },
          ].map(t => `
            <div class="q-card p-2.5 flex items-start gap-2 text-[12px]">
              <span class="text-base shrink-0">${t.icon}</span>
              <span class="leading-snug text-ink/85 dark:text-paper/85">${t.text}</span>
            </div>`).join('')}
        </div>
      </div>

      <!-- Recuperação -->
      <div>
        <div class="text-[10px] uppercase tracking-widest text-ink/55 dark:text-paper/55 mb-2">🛌 Recuperação</div>
        <div class="space-y-1.5">
          ${[
            { icon: '😴', text: 'Sono 7-9h é NÃO-NEGOCIÁVEL. Pouco sono = mais fome + menos músculo preservado.' },
            { icon: '💧', text: '35-40ml de água/kg de peso. Hidratação afeta apetite e performance.' },
            { icon: '🧂', text: 'Eletrólitos (sódio/potássio/magnésio) — cutting reduz retenção. Suplementar.' },
            { icon: '🧘', text: 'Stress controlado. Cortisol alto sabota cutting (retenção + fome).' },
          ].map(t => `
            <div class="q-card p-2.5 flex items-start gap-2 text-[12px]">
              <span class="text-base shrink-0">${t.icon}</span>
              <span class="leading-snug text-ink/85 dark:text-paper/85">${t.text}</span>
            </div>`).join('')}
        </div>
      </div>

      <!-- Quando parar -->
      <div class="q-card p-3" style="border-left:3px solid #FFD341">
        <div class="text-[10px] uppercase tracking-widest font-bold mb-1" style="color:#FFD341">⚠️ Quando parar</div>
        <p class="text-[11px] text-ink/75 dark:text-paper/75 leading-snug">
          Cutting prolongado (>12 semanas) cai performance, libido e humor.
          Faz <b>diet break</b> de 1-2 semanas em manutenção a cada 8-10 semanas
          de déficit. Mais sustentável que cutting agressivo.
        </p>
      </div>

      <!-- CTA de fechar (acessível, visível, claro) -->
      <button class="q-btn q-btn-primary w-full mt-2 modal-close" aria-label="Fechar guia de cutting">
        ← Voltar para Corpo
      </button>
      <p class="text-[10px] text-center text-ink/45 dark:text-paper/45 italic">
        Toque fora do guia também fecha.
      </p>

    </div>
  `);
}

function modalExternalImport() {
  openModal(`
    <header class="flex items-center justify-between p-4 border-b border-ink/5 dark:border-paper/5">
      <div>
        <div class="kombat-tagline text-[10px]">EXTERNAL IMPORT</div>
        <h2 class="font-extrabold text-lg mt-0.5">Importar de Polar / Garmin / Strava</h2>
        <p class="text-[10px] text-ink/55 dark:text-paper/55">Carrega TCX/GPX ou cola o resumo da atividade.</p>
      </div>
      <button class="modal-close p-1"><span class="w-5 h-5">${I.close}</span></button>
    </header>
    <div class="p-4 overflow-y-auto space-y-4" style="max-height:75vh">

      <!-- Opção 1: Upload arquivo -->
      <div class="q-card p-3">
        <div class="font-bold text-sm mb-1">📁 Upload arquivo TCX/GPX</div>
        <p class="text-[11px] text-ink/55 dark:text-paper/55 mb-2 leading-snug">
          No Polar Flow web: Diário → toca na atividade → menu (⋯) → <b>Exportar como TCX</b>.
          No Garmin/Strava também é Export → TCX/GPX.
        </p>
        <label class="q-btn q-btn-ghost w-full text-sm cursor-pointer">
          <input type="file" id="ext-file-input" accept=".tcx,.gpx,.xml" class="hidden" />
          📂 Escolher arquivo
        </label>
        <div id="ext-file-result" class="mt-2 text-xs"></div>
      </div>

      <div class="text-center text-[10px] uppercase tracking-widest text-ink/40 dark:text-paper/40">— ou —</div>

      <!-- Opção 2: Paste texto -->
      <div class="q-card p-3">
        <div class="font-bold text-sm mb-1">📋 Colar resumo</div>
        <p class="text-[11px] text-ink/55 dark:text-paper/55 mb-2 leading-snug">
          Cola o texto da atividade. Detecta automaticamente duração, distância, FC e calorias.
        </p>
        <textarea id="ext-paste-input" class="q-input text-xs" rows="3"
          placeholder="ex: Corrida · 5.2 km · 31:25 · FC média 156 bpm · 412 kcal"></textarea>
        <button id="ext-paste-parse" class="q-btn q-btn-ghost w-full mt-2 text-sm">Analisar</button>
        <div id="ext-paste-result" class="mt-2 text-xs"></div>
      </div>

      <!-- Form de confirmação -->
      <div class="q-card p-3 hidden" id="ext-confirm">
        <div class="font-bold text-sm mb-2">✓ Pronto pra salvar</div>
        <div class="space-y-2">
          <label class="block text-xs">Esporte
            <input id="ext-sport" class="q-input mt-1 text-sm" placeholder="ex: Corrida" />
          </label>
          <div class="grid grid-cols-2 gap-2">
            <label class="block text-xs">Duração (min)
              <input id="ext-duration" class="q-input mt-1 text-sm" type="number" min="0" />
            </label>
            <label class="block text-xs">Distância (km)
              <input id="ext-distance" class="q-input mt-1 text-sm" type="number" step="0.01" min="0" />
            </label>
            <label class="block text-xs">FC média (bpm)
              <input id="ext-hr" class="q-input mt-1 text-sm" type="number" min="0" max="220" />
            </label>
            <label class="block text-xs">Calorias
              <input id="ext-kcal" class="q-input mt-1 text-sm" type="number" min="0" />
            </label>
          </div>
          <label class="block text-xs">Data
            <input id="ext-date" class="q-input mt-1 text-sm" type="date" max="${todayISO()}" />
          </label>
        </div>
        <button id="ext-save" class="q-btn q-btn-primary w-full mt-3">Salvar como treino</button>
      </div>
    </div>
  `, { persistent: true });

  function showConfirm(data) {
    const card = document.getElementById('ext-confirm');
    card.classList.remove('hidden');
    document.getElementById('ext-sport').value    = data.sport || 'Cardio';
    document.getElementById('ext-duration').value = data.durationMin || '';
    document.getElementById('ext-distance').value = data.distanceKm  || '';
    document.getElementById('ext-hr').value       = data.avgHr || '';
    document.getElementById('ext-kcal').value     = data.kcal || '';
    document.getElementById('ext-date').value     = (data.date && data.date <= todayISO()) ? data.date : todayISO();
    card.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
  }

  document.getElementById('ext-file-input').addEventListener('change', async (e) => {
    const file = e.target.files?.[0];
    const result = document.getElementById('ext-file-result');
    if (!file) return;
    result.innerHTML = '<span class="text-ink/55 dark:text-paper/55">📖 Lendo arquivo...</span>';
    try {
      const text = await file.text();
      let data;
      if (/\.gpx$/i.test(file.name) || /<gpx/i.test(text.slice(0, 200))) data = parseGpxFile(text);
      else data = parseTcxFile(text);
      if (!data) { result.innerHTML = '<span class="text-pink">❌ Arquivo não reconhecido. Use TCX ou GPX.</span>'; return; }
      result.innerHTML = `<span class="text-mint">✓ ${data.sport} · ${data.durationMin}min · ${data.distanceKm || 0}km${data.avgHr ? ` · ${data.avgHr}bpm` : ''}${data.kcal ? ` · ${data.kcal}kcal` : ''}</span>`;
      showConfirm(data);
    } catch (err) {
      result.innerHTML = `<span class="text-pink">❌ Erro lendo: ${err.message}</span>`;
    }
  });

  document.getElementById('ext-paste-parse').addEventListener('click', () => {
    const text = document.getElementById('ext-paste-input').value.trim();
    const result = document.getElementById('ext-paste-result');
    if (!text) { result.innerHTML = '<span class="text-pink">Cole o resumo primeiro.</span>'; return; }
    const data = parsePastedSummary(text);
    if (!data.durationMin) { result.innerHTML = '<span class="text-pink">Não consegui detectar duração. Confere o formato.</span>'; return; }
    result.innerHTML = `<span class="text-mint">✓ ${data.sport} · ${data.durationMin}min${data.distanceKm ? ` · ${data.distanceKm}km` : ''}${data.avgHr ? ` · ${data.avgHr}bpm` : ''}${data.kcal ? ` · ${data.kcal}kcal` : ''}</span>`;
    showConfirm(data);
  });

  document.getElementById('ext-save').addEventListener('click', () => {
    const sport      = document.getElementById('ext-sport').value.trim() || 'Cardio';
    const duration   = +document.getElementById('ext-duration').value || 0;
    const distance   = +document.getElementById('ext-distance').value || 0;
    const hr         = +document.getElementById('ext-hr').value || 0;
    const kcal       = +document.getElementById('ext-kcal').value || 0;
    const date       = document.getElementById('ext-date').value || todayISO();
    if (!duration) { toast('Duração obrigatória'); return; }
    // Salva como workout cardio: 1 exercício com técnica = sport, reps = minutos, weight = km
    const workout = {
      date,
      type: tcxSportToQuestType(sport),
      exercises: [{
        name: `${sport} (import)`,
        sets: [{
          reps: String(duration),
          weight: String(distance || ''),
          technique: hr ? `${hr}bpm` : '',
          notes: kcal ? `${kcal} kcal` : '',
        }],
      }],
      importedFrom: 'external',
    };
    const idx = state.workouts.findIndex(w => w.date === workout.date && w.type === workout.type && w.exercises[0]?.name === workout.exercises[0].name);
    if (idx >= 0) state.workouts[idx] = workout;
    else state.workouts.push(workout);
    // XP: base 3 + 1 por 15min de duração (cap 8)
    const xp = Math.min(11, 3 + Math.floor(duration / 15));
    const change = addQuestXP(xp, 'cardio');
    logBattleEvent(`⌚ Import: ${sport} ${duration}min · +${change.finalAmt || xp} XP`, 'gain');
    // Marca treino do dia no log
    if (date === todayISO()) {
      let log = state.dailyLogs.find(l => l.date === date);
      if (!log) {
        log = { date, training: { type: workout.type, done: true }, protein:{grams:0,hit:false},
                sleep:{hours:0}, reading:{minutes:0}, steps:0, buffs:[], notes:'', meals:[], xp:0 };
        state.dailyLogs.push(log);
      } else { log.training = { type: workout.type, done: true }; }
      log.xp = Math.max(log.xp || 0, computeDayXP(log));
    }
    saveState();
    closeModal();
    confetti(900);
    toast(`✓ Importado: ${sport} ${duration}min · +${change.finalAmt || xp} XP`, 3000);
    if (change.changed) setTimeout(() => levelUpOverlay(change.from, change.to, change.promoted), 800);
    render();
  });
}

