/** XP de quests (daily/weekly) — não passa pelo cap diário do log,
 *  e cada quest soma +1 ao contador total (achievement caçador). */
function addQuestXP(amount, tag) {
  const today = todayISO();
  let log = state.dailyLogs.find((l) => l.date === today);
  if (!log) {
    log = {
      date: today,
      training: { type: 'descanso', done: false },
      protein: { grams: 0, hit: false },
      sleep: { hours: 0 },
      reading: { minutes: 0 },
      steps: 0, buffs: [], notes: '', meals: [],
      xp: 0,
    };
    state.dailyLogs.push(log);
  }
  log.xp = (log.xp || 0) + amount;
  if (amount > 0) state.user.questsCompleted = (state.user.questsCompleted || 0) + 1;
  // Mapeia tag → atributo (vitalidade é o default das quests gerais)
  const attrMap = {
    treino: 'forca', cardio: 'resistencia', foco: 'sabedoria',
    nutri: 'disciplina', sono: 'disciplina', saúde: 'vitalidade',
    mente: 'vitalidade', 'k-pop': 'vitalidade',
  };
  const attr = attrMap[tag] || 'vitalidade';
  return gainXP(amount, { attr });
}

function bindFoodRows() {
  document.querySelectorAll('.food-row').forEach((b) => b.onclick = () => {
    const name = decodeURIComponent(b.dataset.name);
    modalFoodPortion(name);
  });
}

// ===== Helpers de formatação =================================

/** "tempo desde" curto: "agora", "12min", "3h", "2d", "1sem". */
function timeAgoShort(d) {
  const ms = Date.now() - d.getTime();
  if (isNaN(ms) || ms < 0) return '';
  const s = Math.floor(ms / 1000);
  if (s < 60) return 'agora';
  const m = Math.floor(s / 60);
  if (m < 60) return `${m}min`;
  const h = Math.floor(m / 60);
  if (h < 24) return `${h}h`;
  const dd = Math.floor(h / 24);
  if (dd < 7) return `${dd}d`;
  const w = Math.floor(dd / 7);
  if (w < 4) return `${w}sem`;
  const mo = Math.floor(dd / 30);
  return `${mo}mes`;
}

function formatDateBR(iso) {
  // Strings YYYY-MM-DD parseiam como UTC; em fusos negativos viram o dia anterior.
  // Interpreta como data local pra evitar esse off-by-one.
  if (typeof iso === 'string' && /^\d{4}-\d{2}-\d{2}$/.test(iso)) {
    const [y, m, d] = iso.split('-').map(Number);
    return new Date(y, m - 1, d).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' });
  }
  return new Date(iso).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' });
}
function formatTime(iso) {
  return new Date(iso).toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
}

// ===== 8. INIT ===============================================

/** Roda toda segunda-feira (ou no primeiro carregamento da nova semana).
 *  1) Registra histórico da semana anterior.
 *  2) Aplica decay no rankXP — esse é o "atrito" que dificulta segurar tiers altos.
 *  3) Desbloqueia skins por 3 semanas Platina+ seguidas. */
function checkWeeklyRollover() {
  const thisWeekStart = isoDate(startOfWeek());
  if (state.settings.lastDecayWeek === thisWeekStart) return;

  const prevStart = new Date(startOfWeek());
  prevStart.setDate(prevStart.getDate() - 7);
  const prevISO = isoDate(prevStart);

  if (!state.rankHistory.find(r => r.weekStart === prevISO)) {
    const xp = state.dailyLogs
      .filter(l => new Date(l.date) >= prevStart && new Date(l.date) < startOfWeek())
      .reduce((s, l) => s + (l.xp || 0), 0);
    if (xp > 0 || state.user.rankXP > 0) {
      // Aplica decay ANTES de registrar o snapshot (representa "semana fechada")
      const before = rankFromXP(state.user.rankXP);
      state.user.rankXP = Math.floor(state.user.rankXP * (1 - RANK_DECAY));
      const after = rankFromXP(state.user.rankXP);
      state.user.currentRank = after.key;

      const rk = rankFromXP(state.user.rankXP);
      state.rankHistory.push({
        weekStart: prevISO,
        rank: rk.key,
        xp,
        rankXP: state.user.rankXP,
      });

      // Skin: 3 semanas Platina+ seguidas (qualquer divisão)
      const last3 = state.rankHistory.slice(-3);
      const elite = new Set(['platinum','emerald','diamond','master','gm','challenger']);
      if (last3.length === 3 && last3.every(r => elite.has(baseRankOf(r.rank)))) {
        const newSkin = `Skin K-${state.rankHistory.length}`;
        if (!state.rewards.unlocked.includes(newSkin)) {
          state.rewards.unlocked.push(newSkin);
          setTimeout(() => toast(`🌟 Skin desbloqueada: ${newSkin}`), 600);
        }
      }
      // Avisa rebaixamento por decay (não overlay para não assustar logo na abertura)
      if (before.key !== after.key && RANKS.indexOf(after) < RANKS.indexOf(before)) {
        setTimeout(() => toast(`📉 Rebaixado por inatividade: ${after.name}`), 300);
      }
    }
  }
  state.settings.lastDecayWeek = thisWeekStart;
  saveState();
}

async function init() {
  // Espera o módulo Firebase carregar (max 1.5s; depois cai pra modo local).
  await waitForCloud();

  if (cloudReady()) {
    // Modo cloud: o estado de auth do Firebase rege a tela.
    showAuthLoading();
    window.QuestCloud.onAuthStateChanged(window.QuestCloud.auth, async (user) => {
      if (!user) { showAuthScreen(); return; }
      await bootGameState();
    });
    return;
  }

  // Modo local (fallback).
  const session = getSession();
  if (!session) { showAuthScreen(); return; }
  const acc = loadAccounts().find((a) => a.id === session);
  if (!acc) { setSession(null); showAuthScreen(); return; }
  bootGameState();
}

function showAuthLoading() {
  document.getElementById('tabbar').innerHTML = '';
  document.getElementById('app').innerHTML = `
    <div class="px-5 pt-16 text-center">
      <div class="kombat-tagline text-xs">⚔ QUEST ⚔</div>
      <div class="text-sm text-ink/55 dark:text-paper/55 mt-4">Conectando…</div>
    </div>`;
}

/** Adiciona um evento ao battle log em memória (state.user.battleLog).
 *  Cap em 50 entries pra não inchar localStorage. */
function logBattleEvent(text, kind = 'gain') {
  if (!state?.user) return;
  state.user.battleLog = state.user.battleLog || [];
  state.user.battleLog.unshift({ ts: Date.now(), text, kind });
  if (state.user.battleLog.length > 50) state.user.battleLog.length = 50;
}

/** Recompensa de login diário — primeira abertura do dia. XP escala com streak
 *  consecutivo de dias logando (capped em 7). Mostra overlay celebrativo. */
// ===== Daily Spin — gacha estilo wheel of fortune 1x/dia =====
// Cada prêmio tem rarity (común/raro/épico/lendário) com taxa de drop
// e efeito real (XP, buff visual, título).
const DAILY_SPIN_PRIZES = [
  { id: 'xp_small',   label: '+3 XP',      kind: 'xp',    value: 3,  rarity: 'common',    color: '#A8E6CF', weight: 30 },
  { id: 'xp_med',     label: '+5 XP',      kind: 'xp',    value: 5,  rarity: 'common',    color: '#A8E6CF', weight: 20 },
  { id: 'xp_big',     label: '+10 XP',     kind: 'xp',    value: 10, rarity: 'rare',      color: '#7BB8FF', weight: 12 },
  { id: 'combo_x2',   label: '⚡ Combo ×2 (1h)', kind: 'combo', value: 2,  rarity: 'rare',      color: '#FFD341', weight: 10 },
  { id: 'combo_x3',   label: '⚡ Combo ×3 (30min)', kind: 'combo', value: 3,  rarity: 'epic',  color: '#C77BFF', weight: 5 },
  { id: 'xp_huge',    label: '+25 XP',     kind: 'xp',    value: 25, rarity: 'epic',      color: '#C77BFF', weight: 4 },
  { id: 'title_lucky',label: '🍀 Título: Lucky', kind: 'title', value: 'Lucky', rarity: 'epic', color: '#3FBF7F', weight: 3 },
  { id: 'xp_jackpot', label: '🎰 JACKPOT +50 XP', kind: 'xp', value: 50, rarity: 'legendary', color: '#FFD341', weight: 1 },
  { id: 'rerollfree', label: '🎲 Re-roll grátis', kind: 'reroll', value: 1, rarity: 'common',  color: '#A8E6CF', weight: 15 },
];

function weightedRandomPrize() {
  const total = DAILY_SPIN_PRIZES.reduce((s, p) => s + p.weight, 0);
  let r = Math.random() * total;
  for (const p of DAILY_SPIN_PRIZES) {
    r -= p.weight;
    if (r <= 0) return p;
  }
  return DAILY_SPIN_PRIZES[0];
}

function spinDailyWheel() {
  if (!state?.user) return;
  const today = todayISO();
  if (state.user.lastSpinDate === today) {
    toast('Você já girou hoje. Volta amanhã!');
    return;
  }
  const prize = weightedRandomPrize();
  state.user.lastSpinDate = today;

  // Aplica o prêmio
  let xpGained = 0;
  if (prize.kind === 'xp') {
    const change = addQuestXP(prize.value, 'vitalidade');
    xpGained = change.finalAmt || prize.value;
    if (change.changed) setTimeout(() => levelUpOverlay(change.from, change.to, change.promoted), 2200);
  } else if (prize.kind === 'combo') {
    state.user.spinCombo = { mult: prize.value, until: Date.now() + (prize.value === 2 ? 60 : 30) * 60 * 1000 };
  } else if (prize.kind === 'title') {
    state.user.spinTitle = prize.value;
  } else if (prize.kind === 'reroll') {
    state.user.bonusRerolls = (state.user.bonusRerolls || 0) + 1;
  }
  logBattleEvent(`🎰 Spin: ${prize.label} (${prize.rarity})`, prize.rarity === 'legendary' ? 'pr' : 'gain');
  saveState();
  showSpinResultOverlay(prize, xpGained);
}

function showSpinResultOverlay(prize, xpGained) {
  const rarityLabel = {
    common:    'COMUM',
    rare:      'RARO ✦',
    epic:      'ÉPICO ✦✦',
    legendary: 'LENDÁRIO ✦✦✦',
  }[prize.rarity];
  const rarityGlow = {
    common:    'rgba(168,230,207,0.6)',
    rare:      'rgba(123,184,255,0.7)',
    epic:      'rgba(199,123,255,0.8)',
    legendary: 'rgba(255,211,65,1)',
  }[prize.rarity];
  const overlay = document.createElement('div');
  overlay.className = 'spin-overlay';
  overlay.innerHTML = `
    <div class="spin-card" style="border-color:${prize.color}; box-shadow: 0 0 80px ${rarityGlow}, 0 0 0 3px ${prize.color}55 inset">
      <div class="text-[10px] uppercase tracking-[0.3em] font-bold opacity-65">DAILY SPIN</div>
      <div class="text-[11px] uppercase tracking-widest mt-1 font-extrabold" style="color:${prize.color}">${rarityLabel}</div>
      <div class="text-6xl mt-3">🎰</div>
      <div class="text-2xl font-extrabold mt-2" style="color:${prize.color}">${prize.label}</div>
      ${xpGained ? `<div class="text-sm mt-1 opacity-80">+${xpGained} XP recebido</div>` : ''}
      <button class="mt-5 px-5 py-2 rounded-full text-sm font-bold dismiss-spin" style="background:${prize.color}; color:#1A1A2E">Continuar</button>
    </div>`;
  document.body.appendChild(overlay);
  vibrate([40, 30, 60, 30, 100]);
  if (prize.rarity === 'legendary' || prize.rarity === 'epic') confetti(2200);
  else confetti(1200);
  const close = () => { overlay.classList.add('is-closing'); setTimeout(() => { overlay.remove(); render(); }, 250); };
  overlay.querySelector('.dismiss-spin').onclick = close;
  overlay.onclick = (e) => { if (e.target === overlay) close(); };
  setTimeout(close, 4500);
}

function checkDailyLoginBonus() {
  if (!state?.user) return;
  const today = todayISO();
  const last = state.user.lastLoginDate;
  if (last === today) return; // já recebeu hoje
  // Calcula streak: se logou ONTEM, continua; senão zera.
  const yesterday = new Date(today + 'T00:00:00'); yesterday.setDate(yesterday.getDate() - 1);
  const yISO = isoDate(yesterday);
  const prevStreak = state.user.loginStreak || 0;
  const newStreak = last === yISO ? prevStreak + 1 : 1;
  // XP escala: dia 1=2, dia 2=3, ..., dia 7+=10. Combo de 7 dias = +10 bônus extra.
  const xp = Math.min(10, 1 + newStreak);
  state.user.lastLoginDate = today;
  state.user.loginStreak = newStreak;
  const change = addQuestXP(xp, 'vitalidade');
  logBattleEvent(`☀️ Login dia ${newStreak} · +${xp} XP`);
  saveState();
  // Overlay celebrativo
  setTimeout(() => showLoginBonusOverlay(xp, newStreak), 600);
  if (change.changed) setTimeout(() => levelUpOverlay(change.from, change.to, change.promoted), 2200);
}

function showLoginBonusOverlay(xp, streak) {
  const overlay = document.createElement('div');
  overlay.className = 'login-bonus-overlay';
  overlay.innerHTML = `
    <div class="login-bonus-card">
      <div class="text-[10px] uppercase tracking-[0.3em] font-bold opacity-70">DAILY BONUS</div>
      <div class="text-5xl mt-2">☀️</div>
      <div class="text-2xl font-extrabold mt-2">+${xp} XP</div>
      <div class="text-sm mt-1 opacity-80">Streak de login: <b>${streak} dia${streak === 1 ? '' : 's'}</b></div>
      ${streak >= 7 ? '<div class="text-xs mt-2 text-kgold font-bold">🔥 7+ dias! Streak quente!</div>' : ''}
      ${streak >= 30 ? '<div class="text-xs mt-1 text-mint font-bold">💎 30 dias — você é compromisso puro!</div>' : ''}
      <button class="mt-4 px-4 py-2 rounded-full bg-paper text-ink text-sm font-bold dismiss-bonus">Continuar</button>
    </div>`;
  document.body.appendChild(overlay);
  vibrate([30, 30, 60]);
  confetti(1200);
  const close = () => { overlay.classList.add('is-closing'); setTimeout(() => overlay.remove(), 250); };
  overlay.querySelector('.dismiss-bonus').onclick = close;
  overlay.onclick = (e) => { if (e.target === overlay) close(); };
  setTimeout(close, 3500);
}

async function bootGameState() {
  // 1) Carrega cache local pra UI instantânea
  let local = loadState();
  // 2) Se tiver Firebase, busca o state da nuvem e mescla com fotos locais
  if (cloudReady() && window.QuestCloud.auth.currentUser) {
    const cloud = await loadCloudState(window.QuestCloud.auth.currentUser.uid);
    if (cloud) {
      state = mergeWithLocalMedia(cloud, local);
    } else if (local) {
      state = local;
    } else {
      state = makeEmptyState();
      const acc = currentAccount();
      if (acc) state.user.name = acc.username;
    }
    // Migra: state local pré-existente sem nuvem → faz upload inicial
    migrateState(state);
    saveState();
  } else {
    state = local;
    if (!state) {
      state = makeEmptyState();
      const acc = currentAccount();
      if (acc) state.user.name = acc.username;
      saveState();
    }
  }
  if (state.user.darkMode) document.documentElement.classList.add('dark');
  applyTheme();
  ensureDailyQuests();
  ensureWeeklyQuest();
  checkWeeklyRollover();
  setTimeout(checkAchievements, 100);
  setTimeout(maybeNotifyMascot, 1500);
  // Daily Login Bonus — primeira abertura do dia ganha XP de presença
  setTimeout(checkDailyLoginBonus, 800);
  // Atualiza timer ao voltar pra tab (Page Visibility API)
  if (!window._restVisHook) {
    window._restVisHook = true;
    document.addEventListener('visibilitychange', () => {
      if (!document.hidden) updateRestTimerDisplay();
    });
  }
  // Spotify OAuth callback — se voltou de accounts.spotify.com com ?code=
  // troca por token (state já carregado, então tem o clientId disponível).
  if (new URLSearchParams(window.location.search).has('code')) {
    await spotifyHandleCallback();
  }
  render();
}

/** Envia notificação Web do mascote 1x por dia (se o usuário permitiu).
 *  Forma muda conforme nutri do dia — alerta visual fora do app. */
async function maybeNotifyMascot() {
  if (!('Notification' in window)) return;
  if (Notification.permission === 'denied') return;
  const today = todayISO();
  if (state.user.mascotNotifiedAt === today) return;
  // Pede permissão sem ser invasivo (só se ainda não escolheu)
  if (Notification.permission === 'default') {
    try {
      const result = await Notification.requestPermission();
      if (result !== 'granted') return;
    } catch { return; }
  }
  if (Notification.permission !== 'granted') return;
  const m = mascotState();
  const formLabel = { magro: 'magrinho', musculoso: 'musculoso', gordo: 'fofinho', neutro: 'tranquilo' };
  try {
    new Notification(`${m.emoji} ${m.name} tá ${formLabel[m.formDay]}`, {
      body: m.adviceDay,
      icon: 'icons/icon-192.png',
      tag: 'quest-mascot-' + today,
    });
    state.user.mascotNotifiedAt = today;
    saveState();
  } catch (e) {
    console.warn('mascot notify failed:', e);
  }
}

/** Aplica o tema do usuário (data-theme no <html>). */
function applyTheme() {
  const t = state?.user?.theme && THEMES[state.user.theme] ? state.user.theme : 'kpop_anime';
  document.documentElement.dataset.theme = t;
  applyCharacterTheme();
  // Modo sensorial reduzido — desativa animações, confetti, vibração (CSS faz o resto)
  const lowSensory = !!state?.user?.profile?.lowSensory;
  document.documentElement.dataset.lowSensory = lowSensory ? 'true' : '';
}

/** Helper: pula vibração e confetti quando lowSensory está ativo. */
function reducedMotion() {
  return !!state?.user?.profile?.lowSensory;
}

// ===== 5.5 SPOTIFY ============================================
// OAuth PKCE flow (sem client_secret — perfeito pra apps client-only).
// Tokens em state.user.spotify. Refresh automático ao expirar.
// Polling do now-playing controlado por _spotifyPollInterval.

const SPOTIFY_SCOPES = [
  'user-read-currently-playing',
  'user-read-playback-state',
  'user-modify-playback-state',
].join(' ');

// SVG icons (24×24, fill currentColor) — renderizam idênticos em todas as plataformas,
// diferente dos emojis ⏮⏯⏭ que ficam tortos no Android/iOS/desktop.
const SP_ICON = {
  prev:  '<svg viewBox="0 0 24 24" fill="currentColor" aria-hidden="true"><path d="M6 6h2v12H6V6zm3.5 6L18 18V6l-8.5 6z"/></svg>',
  play:  '<svg viewBox="0 0 24 24" fill="currentColor" aria-hidden="true"><path d="M7 5.5v13l11-6.5L7 5.5z"/></svg>',
  pause: '<svg viewBox="0 0 24 24" fill="currentColor" aria-hidden="true"><path d="M7 5h3.5v14H7V5zm6.5 0H17v14h-3.5V5z"/></svg>',
  next:  '<svg viewBox="0 0 24 24" fill="currentColor" aria-hidden="true"><path d="M16 6h2v12h-2V6zm-2.5 6L5 6v12l8.5-6z"/></svg>',
};

let _spotifyPollInterval = null;
let _spotifyNowPlaying = null;       // cache da última resposta
let _spotifyLastFetchAt = 0;         // throttle
let _spotifyRefreshPromise = null;   // dedupe de refresh concorrente

/** Retorna a redirect URI usada no auth (mesma página, sem hash/search). */
function spotifyRedirectURI() {
  return window.location.origin + window.location.pathname;
}

/** Gera string aleatória pro PKCE code_verifier (RFC 7636). */
function spotifyRandomVerifier(length = 64) {
  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-._~';
  const arr = new Uint8Array(length);
  crypto.getRandomValues(arr);
  return Array.from(arr, (b) => chars[b % chars.length]).join('');
}

/** SHA-256 base64url do code_verifier → code_challenge. */
async function spotifyChallenge(verifier) {
  const data = new TextEncoder().encode(verifier);
  const buf = await crypto.subtle.digest('SHA-256', data);
  return btoa(String.fromCharCode(...new Uint8Array(buf)))
    .replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
}

/** Inicia o fluxo OAuth — redireciona pro accounts.spotify.com/authorize. */
async function spotifyConnect() {
  const cid = state.user.spotify?.clientId;
  if (!cid) {
    toast('Cole o Client ID em Configurações primeiro');
    return;
  }
  const verifier = spotifyRandomVerifier();
  const challenge = await spotifyChallenge(verifier);
  // Salva o verifier pra usar no callback (sobrevive ao redirect)
  sessionStorage.setItem('spotify_verifier', verifier);
  sessionStorage.setItem('spotify_state', Math.random().toString(36).slice(2));
  const url = 'https://accounts.spotify.com/authorize?' + new URLSearchParams({
    response_type: 'code',
    client_id: cid,
    redirect_uri: spotifyRedirectURI(),
    scope: SPOTIFY_SCOPES,
    code_challenge_method: 'S256',
    code_challenge: challenge,
    state: sessionStorage.getItem('spotify_state'),
  });
  window.location.assign(url);
}

/** Chamado no carregamento da página. Se há ?code= na URL, troca por token. */
async function spotifyHandleCallback() {
  const params = new URLSearchParams(window.location.search);
  const code = params.get('code');
  const stt  = params.get('state');
  const err  = params.get('error');
  if (!code && !err) return false;

  // Limpa URL imediatamente (não deixa code visível no histórico)
  const cleanURL = window.location.origin + window.location.pathname + window.location.hash;
  history.replaceState({}, '', cleanURL);

  if (err) { toast('Spotify: ' + err); return false; }

  const expectedState = sessionStorage.getItem('spotify_state');
  if (!stt || stt !== expectedState) { toast('Spotify: state inválido'); return false; }
  const verifier = sessionStorage.getItem('spotify_verifier');
  if (!verifier) { toast('Spotify: code_verifier perdido'); return false; }

  const cid = state.user.spotify?.clientId;
  try {
    const res = await fetch('https://accounts.spotify.com/api/token', {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: new URLSearchParams({
        grant_type: 'authorization_code',
        code,
        redirect_uri: spotifyRedirectURI(),
        client_id: cid,
        code_verifier: verifier,
      }),
    });
    if (!res.ok) throw new Error('token exchange falhou (' + res.status + ')');
    const j = await res.json();
    state.user.spotify.accessToken  = j.access_token;
    state.user.spotify.refreshToken = j.refresh_token || state.user.spotify.refreshToken;
    state.user.spotify.expiresAt    = Date.now() + (j.expires_in - 30) * 1000;
    state.user.spotify.scope        = j.scope || '';
    saveState();
    sessionStorage.removeItem('spotify_verifier');
    sessionStorage.removeItem('spotify_state');
    toast('Spotify conectado ✓');
    return true;
  } catch (e) {
    console.error(e);
    toast('Spotify: falha ao conectar');
    return false;
  }
}

/** Refresh do access token quando expira. Dedupe via promise compartilhada. */
async function spotifyRefresh() {
  if (_spotifyRefreshPromise) return _spotifyRefreshPromise;
  const sp = state.user.spotify;
  if (!sp.refreshToken || !sp.clientId) return false;
  _spotifyRefreshPromise = (async () => {
    try {
      const res = await fetch('https://accounts.spotify.com/api/token', {
        method: 'POST',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: new URLSearchParams({
          grant_type: 'refresh_token',
          refresh_token: sp.refreshToken,
          client_id: sp.clientId,
        }),
      });
      if (!res.ok) throw new Error('refresh falhou');
      const j = await res.json();
      sp.accessToken = j.access_token;
      if (j.refresh_token) sp.refreshToken = j.refresh_token;
      sp.expiresAt = Date.now() + (j.expires_in - 30) * 1000;
      saveState();
      return true;
    } catch (e) {
      console.error('Spotify refresh:', e);
      return false;
    } finally {
      _spotifyRefreshPromise = null;
    }
  })();
  return _spotifyRefreshPromise;
}

/** Garante token válido. Faz refresh se expirado. Retorna access token ou null. */
async function spotifyEnsureToken() {
  const sp = state.user.spotify;
  if (!sp.accessToken) return null;
  if (Date.now() >= sp.expiresAt) {
    const ok = await spotifyRefresh();
    if (!ok) return null;
  }
  return sp.accessToken;
}

/** Wrapper de fetch — adiciona Authorization e retenta uma vez no 401. */
async function spotifyFetch(path, opts = {}) {
  let tok = await spotifyEnsureToken();
  if (!tok) return null;
  const doFetch = () => fetch('https://api.spotify.com/v1' + path, {
    ...opts,
    headers: { ...(opts.headers || {}), Authorization: 'Bearer ' + tok },
  });
  let res = await doFetch();
  if (res.status === 401) {
    if (await spotifyRefresh()) {
      tok = state.user.spotify.accessToken;
      res = await doFetch();
    }
  }
  return res;
}

/** Está conectado? (tem clientId + accessToken). */
function spotifyConnected() {
  const sp = state.user?.spotify;
  return !!(sp && sp.clientId && sp.accessToken);
}

/** Desconecta — limpa tokens (mantém clientId pra reconectar fácil). */
function spotifyDisconnect() {
  state.user.spotify.accessToken = '';
  state.user.spotify.refreshToken = '';
  state.user.spotify.expiresAt = 0;
  state.user.spotify.scope = '';
  saveState();
  spotifyStopPolling();
  _spotifyNowPlaying = null;
  toast('Spotify desconectado');
  render();
}

/** Busca o que está tocando agora. Cacheia em _spotifyNowPlaying. */
async function spotifyFetchNowPlaying() {
  if (!spotifyConnected()) { _spotifyNowPlaying = null; return null; }
  const now = Date.now();
  if (now - _spotifyLastFetchAt < 3000) return _spotifyNowPlaying; // throttle 3s
  _spotifyLastFetchAt = now;
  try {
    const res = await spotifyFetch('/me/player/currently-playing');
    if (!res) return null;
    if (res.status === 204) { _spotifyNowPlaying = { idle: true }; return _spotifyNowPlaying; }
    if (!res.ok) return _spotifyNowPlaying; // mantém o último
    const j = await res.json();
    _spotifyNowPlaying = j;
    return j;
  } catch (e) {
    console.error('now-playing:', e);
    return _spotifyNowPlaying;
  }
}

/** Inicia polling do now-playing. Cancela qualquer anterior. */
function spotifyStartPolling(intervalMs = 12000) {
  spotifyStopPolling();
  if (!spotifyConnected()) return;
  // Primeira busca imediata
  spotifyFetchNowPlaying().then(() => updateSpotifyCard());
  _spotifyPollInterval = setInterval(async () => {
    await spotifyFetchNowPlaying();
    updateSpotifyCard();
  }, intervalMs);
}

function spotifyStopPolling() {
  if (_spotifyPollInterval) { clearInterval(_spotifyPollInterval); _spotifyPollInterval = null; }
}

/** Atualiza só o conteúdo do card de spotify (sem re-render completo). */
function updateSpotifyCard() {
  const card = document.querySelector('[data-spotify-card]');
  if (!card) return;
  card.outerHTML = renderSpotifyCard();
  attachSpotifyCardHandlers();
  // Mantém o player modal sincronizado, se estiver aberto
  const playerBody = document.querySelector('[data-spotify-player-body]');
  if (playerBody) {
    playerBody.outerHTML = renderSpotifyPlayerBody();
    attachSpotifyPlayerHandlers();
  }
}

/** Comandos de playback (Premium-only — fail-soft com toast). */
async function spotifyCommand(action) {
  if (!spotifyConnected()) return;
  vibrate(8);
  const map = {
    next:  { path: '/me/player/next',     method: 'POST' },
    prev:  { path: '/me/player/previous', method: 'POST' },
    play:  { path: '/me/player/play',     method: 'PUT' },
    pause: { path: '/me/player/pause',    method: 'PUT' },
  };
  const cfg = map[action];
  if (!cfg) return;
  try {
    const res = await spotifyFetch(cfg.path, { method: cfg.method });
    if (res?.status === 403) toast('Premium necessário pra controlar');
    else if (res?.status === 404) toast('Nenhum aparelho ativo no Spotify');
    // Espera ~600ms pro Spotify processar e depois pega o novo estado
    setTimeout(async () => { await spotifyFetchNowPlaying(); updateSpotifyCard(); }, 700);
  } catch (e) {
    console.error('spotify cmd:', e);
  }
}

/** Renderiza o card do Spotify (cobre quote do dia na home). */
function renderSpotifyCard() {
  const sp = state.user.spotify;
  if (!sp.clientId) {
    return `
    <div class="spotify-card spotify-empty" data-spotify-card>
      <div class="spotify-empty-icon">🎵</div>
      <div class="spotify-empty-text">
        <div class="font-bold text-sm">Conecte o Spotify</div>
        <div class="text-[10px] text-ink/55 dark:text-paper/55">Cole seu Client ID em Configurações</div>
      </div>
      <button class="q-btn q-btn-ghost text-[10px]" data-go-config>→ Config</button>
    </div>`;
  }
  if (!sp.accessToken) {
    return `
    <div class="spotify-card spotify-empty" data-spotify-card>
      <div class="spotify-empty-icon">🎵</div>
      <div class="spotify-empty-text">
        <div class="font-bold text-sm">Spotify</div>
        <div class="text-[10px] text-ink/55 dark:text-paper/55">Toque pra autorizar</div>
      </div>
      <button class="q-btn q-btn-primary text-[10px]" data-spotify-connect>Conectar</button>
    </div>`;
  }
  const np = _spotifyNowPlaying;
  if (!np || np.idle || !np.item) {
    return `
    <div class="spotify-card spotify-empty" data-spotify-card>
      <div class="spotify-empty-icon">⏸</div>
      <div class="spotify-empty-text">
        <div class="font-bold text-sm">Nada tocando</div>
        <div class="text-[10px] text-ink/55 dark:text-paper/55">Abre o Spotify e dá play</div>
      </div>
      <button class="q-btn q-btn-ghost text-[10px]" data-spotify-refresh>↻</button>
    </div>`;
  }
  const t = np.item;
  const artists = (t.artists || []).map(a => a.name).join(', ');
  const cover = t.album?.images?.[0]?.url || '';
  const progress = np.progress_ms || 0;
  const duration = t.duration_ms || 1;
  const pct = Math.min(100, (progress / duration) * 100);
  const playing = np.is_playing;
  return `
  <button class="spotify-card spotify-playing" data-spotify-card data-spotify-open>
    <div class="spotify-cover">
      ${cover ? `<img src="${cover}" alt="${t.album?.name || ''}" />` : '🎵'}
      ${playing ? '<div class="spotify-eq"><span></span><span></span><span></span></div>' : ''}
    </div>
    <div class="spotify-meta">
      <div class="spotify-eyebrow">${playing ? '▶ NOW PLAYING' : '⏸ PAUSADO'}</div>
      <div class="spotify-track">${t.name}</div>
      <div class="spotify-artist">${artists}</div>
      <div class="spotify-progress"><span style="width:${pct}%"></span></div>
    </div>
    <div class="spotify-quick">
      <span data-spotify-cmd="prev" title="Anterior" aria-label="Anterior">${SP_ICON.prev}</span>
      <span data-spotify-cmd="${playing ? 'pause' : 'play'}" class="is-main" title="${playing ? 'Pausar' : 'Tocar'}" aria-label="${playing ? 'Pausar' : 'Tocar'}">${playing ? SP_ICON.pause : SP_ICON.play}</span>
      <span data-spotify-cmd="next" title="Próxima" aria-label="Próxima">${SP_ICON.next}</span>
    </div>
  </button>`;
}

/** Liga os clicks do card. */
function attachSpotifyCardHandlers() {
  // Clique em qualquer botão de comando — para a propagação pra não abrir o player
  document.querySelectorAll('[data-spotify-cmd]').forEach((el) => {
    el.onclick = (ev) => {
      ev.stopPropagation();
      ev.preventDefault();
      spotifyCommand(el.dataset.spotifyCmd);
    };
  });
  document.querySelector('[data-spotify-open]')?.addEventListener('click', (ev) => {
    if (ev.target.closest('[data-spotify-cmd]')) return; // já tratado acima
    if (!spotifyConnected() || !_spotifyNowPlaying?.item) return;
    modalSpotifyPlayer();
  });
  document.querySelector('[data-spotify-connect]')?.addEventListener('click', () => {
    spotifyConnect();
  });
  document.querySelector('[data-spotify-refresh]')?.addEventListener('click', async () => {
    _spotifyLastFetchAt = 0;
    await spotifyFetchNowPlaying();
    updateSpotifyCard();
  });
  document.querySelector('[data-go-config]')?.addEventListener('click', () => {
    currentTab = 'config'; render();
    setTimeout(() => document.getElementById('cfg-spotify-cid')?.focus(), 100);
  });
}

/** Modal full player — capa grande, controles, fila. */
function modalSpotifyPlayer() {
  vibrate(10);
  openModal(`
    <div class="spotify-player">
      <button class="workout-hero-btn workout-hero-btn-right modal-close">✕</button>
      <div data-spotify-player-body>${renderSpotifyPlayerBody()}</div>
    </div>
  `, { persistent: false });
  attachSpotifyPlayerHandlers();
  // Carrega a fila depois
  spotifyLoadQueue();
}

let _spotifyQueue = null;

async function spotifyLoadQueue() {
  if (!spotifyConnected()) return;
  try {
    const res = await spotifyFetch('/me/player/queue');
    if (res?.ok) {
      _spotifyQueue = await res.json();
      const queueBox = document.querySelector('[data-spotify-queue]');
      if (queueBox) queueBox.outerHTML = renderSpotifyQueue();
      attachSpotifyPlayerHandlers();
    }
  } catch (e) { console.error('queue:', e); }
}

function renderSpotifyPlayerBody() {
  const np = _spotifyNowPlaying;
  if (!np || np.idle || !np.item) {
    return `
      <div class="spotify-player-empty">
        <div class="text-6xl">⏸</div>
        <div class="font-bold mt-3">Nada tocando agora</div>
        <div class="text-xs text-ink/55 dark:text-paper/55 mt-1">Abre o Spotify em qualquer aparelho e dá play</div>
      </div>`;
  }
  const t = np.item;
  const artists = (t.artists || []).map(a => a.name).join(', ');
  const cover = t.album?.images?.[0]?.url || '';
  const album = t.album?.name || '';
  const progress = np.progress_ms || 0;
  const duration = t.duration_ms || 1;
  const pct = Math.min(100, (progress / duration) * 100);
  const fmt = (ms) => {
    const s = Math.floor(ms / 1000), m = Math.floor(s/60), ss = String(s%60).padStart(2,'0');
    return `${m}:${ss}`;
  };
  const playing = np.is_playing;
  return `
    <div class="spotify-player-body">
      <div class="spotify-player-cover">
        ${cover ? `<img src="${cover}" alt="${album}" />` : ''}
      </div>
      <div class="spotify-player-meta">
        <div class="spotify-player-track">${t.name}</div>
        <div class="spotify-player-artist">${artists}</div>
        <div class="spotify-player-album">${album}</div>
      </div>
      <div class="spotify-player-progress">
        <div class="spotify-player-bar"><span style="width:${pct}%"></span></div>
        <div class="spotify-player-times">
          <span>${fmt(progress)}</span>
          <span>${fmt(duration)}</span>
        </div>
      </div>
      <div class="spotify-player-controls">
        <button class="spotify-ctrl" data-spotify-cmd="prev" aria-label="Anterior">${SP_ICON.prev}</button>
        <button class="spotify-ctrl spotify-ctrl-main" data-spotify-cmd="${playing ? 'pause' : 'play'}" aria-label="${playing ? 'Pausar' : 'Tocar'}">${playing ? SP_ICON.pause : SP_ICON.play}</button>
        <button class="spotify-ctrl" data-spotify-cmd="next" aria-label="Próxima">${SP_ICON.next}</button>
      </div>
      ${renderSpotifyQueue()}
    </div>`;
}

function renderSpotifyQueue() {
  if (!_spotifyQueue || !_spotifyQueue.queue?.length) {
    return `<div data-spotify-queue class="spotify-queue-empty">Fila vazia ou carregando…</div>`;
  }
  const items = _spotifyQueue.queue.slice(0, 10).map((tr, i) => `
    <div class="spotify-queue-item">
      <div class="spotify-queue-index">${i + 1}</div>
      <div class="spotify-queue-cover">${tr.album?.images?.[2]?.url ? `<img src="${tr.album.images[2].url}" />` : '♪'}</div>
      <div class="spotify-queue-meta">
        <div class="spotify-queue-name">${tr.name}</div>
        <div class="spotify-queue-artist">${(tr.artists || []).map(a => a.name).join(', ')}</div>
      </div>
    </div>
  `).join('');
  return `
    <div data-spotify-queue class="spotify-queue">
      <div class="spotify-queue-title">PRÓXIMAS NA FILA</div>
      ${items}
    </div>`;
}

function attachSpotifyPlayerHandlers() {
  document.querySelectorAll('.spotify-player [data-spotify-cmd]').forEach((el) => {
    el.onclick = (ev) => {
      ev.stopPropagation();
      spotifyCommand(el.dataset.spotifyCmd);
      // Recarrega a fila após próxima/anterior
      if (el.dataset.spotifyCmd === 'next' || el.dataset.spotifyCmd === 'prev') {
        setTimeout(() => spotifyLoadQueue(), 800);
      }
    };
  });
}

// ===== 5.6 CLAUDE / ANTHROPIC ================================
// Chamada client-side via header anthropic-dangerous-direct-browser-access.
// API key fica no localStorage (state.user.anthropic.apiKey). User aceita o
// risco — recomendação: usar key pessoal com limite de gasto no console.

const AI_MODELS = [
  { id: 'claude-haiku-4-5-20251001', label: 'Haiku 4.5 (rápido, barato)' },
  { id: 'claude-sonnet-4-6',         label: 'Sonnet 4.6 (balanceado)' },
  { id: 'claude-opus-4-8',           label: 'Opus 4.8 (mais inteligente)' },
];

function aiReady() {
  return !!(state.user?.anthropic?.apiKey);
}

/** Chama Claude API. systemPrompt é fixo; userMessage é a query.
 *  Retorna o texto da resposta ou lança erro. */
async function askClaude(systemPrompt, userMessage, opts = {}) {
  const key = state.user?.anthropic?.apiKey;
  if (!key) throw new Error('API key não configurada');
  const model = opts.model || state.user?.anthropic?.model || 'claude-haiku-4-5-20251001';
  const maxTokens = opts.maxTokens || 1024;
  const res = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'x-api-key': key,
      'anthropic-version': '2023-06-01',
      'anthropic-dangerous-direct-browser-access': 'true',
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      model,
      max_tokens: maxTokens,
      system: systemPrompt,
      messages: opts.history ? [...opts.history, { role: 'user', content: userMessage }]
                             : [{ role: 'user', content: userMessage }],
    }),
  });
  if (!res.ok) {
    const text = await res.text().catch(() => '');
    let msg = `HTTP ${res.status}`;
    try { const j = JSON.parse(text); msg = j.error?.message || msg; } catch {}
    throw new Error(msg);
  }
  const j = await res.json();
  return j.content?.[0]?.text || '';
}

/** Constrói o contexto do usuário pra IA — inclui dados físicos E perfil
 *  comportamental. O perfil informa COMO falar (anti-aversivo, baixa carga
 *  executiva, previsibilidade). */
function aiBuildUserContext() {
  if (!state) return '';
  const u = state.user || {};
  const p = u.profile || {};
  const today = todayISO();
  const last7 = (state.dailyLogs || []).slice(-7);
  const trainings = (state.workouts || []).slice(-5);
  const ch = activeCharacter();
  const totalKcal7 = last7.reduce((s,l) => s + (l.meals||[]).reduce((a,m)=>a+(m.kcal||0),0), 0);
  const trainDays7 = last7.filter(l => l.training?.done).length;
  const sleepAvg = last7.reduce((s,l)=>s+(l.sleep?.hours||0),0)/Math.max(1,last7.length);
  const readMin7 = last7.reduce((s,l)=>s+(l.reading?.minutes||0),0);
  const lastWeight = (state.bodyMeasurements||[]).slice(-1)[0]?.weight;
  const r = rankFromXP(u.rankXP||0);
  const GOAL_LABELS = {
    definicao_abs: 'definição corporal (foco abdômen)',
    massa_geral:   'ganho de massa muscular geral',
    peso_off:      'perda de peso / cutting',
    saude:         'saúde geral',
    performance:   'performance esportiva',
  };
  const CONDITION_LABELS = {
    tdah: 'TDAH',
    tag: 'TAG (transtorno de ansiedade generalizada)',
    autismo_possivel: 'possível espectro autista',
    autismo: 'TEA confirmado',
    depressao: 'depressão',
    bipolar: 'bipolaridade',
  };
  return [
    `Nome: ${u.name || 'Operador'}`,
    ch ? `Personagem ativo no app: ${ch.name} · ${ch.title}` : '',
    u.height ? `Altura: ${u.height}cm` : '',
    u.age ? `Idade: ${u.age}` : '',
    u.sex ? `Sexo: ${u.sex==='m'?'masculino':'feminino'}` : '',
    lastWeight ? `Peso atual: ${lastWeight}kg` : '',
    `Rank no app: ${r.name} (${u.rankXP||0} XP)`,
    `Objetivo principal: ${GOAL_LABELS[p.goal] || p.goal || 'não definido'}`,
    p.conditions?.length ? `Condições neurodivergentes/saúde mental: ${p.conditions.map(c => CONDITION_LABELS[c] || c).join(', ')}` : '',
    `Engajamento atual: treino ${p.engagement?.gym || 'medio'} · dieta ${p.engagement?.diet || 'medio'}`,
    p.notes ? `Notas pessoais: ${p.notes}` : '',
    `Últimos 7 dias: ${trainDays7} treinos, ~${Math.round(totalKcal7/Math.max(1,last7.length))} kcal/dia, ~${sleepAvg.toFixed(1)}h sono/dia, ${readMin7}min lendo`,
    trainings.length ? `Últimos treinos registrados: ${trainings.map(t=>t.type).join(', ')}` : '',
    `Data de hoje: ${today}`,
  ].filter(Boolean).join('\n');
}

/** System prompt base — princípios de análise funcional aplicados.
 *  Anti-aversivo, baixa carga executiva, validação > prescrição. */
function aiCoachSystemPrompt() {
  const p = state.user?.profile || {};
  const hasNeurodivergence = p.conditions?.length > 0;
  return `Você é Claude, integrado no app QUEST como coach de hábitos do usuário. Responde em pt-BR.

PRINCÍPIOS DE COMUNICAÇÃO (siga todos sempre):

1. ANTI-AVERSIVO. Nunca use:
   - "você falhou", "perdeu", "atrasado", "está caindo"
   - listas longas de "o que você deveria fazer"
   - tom de cobrança ou comparação com outros
   Em vez disso: foque no que JÁ ESTÁ funcionando, valide a tentativa.

2. BAIXA CARGA EXECUTIVA (TDAH-friendly):
   - 1 sugestão por vez, nunca 5
   - ação concreta e ESPECÍFICA ("coma 1 ovo agora" não "tente mais proteína")
   - se for explicar algo, use 2 parágrafos curtos no MÁXIMO
   - resposta total entre 40 e 120 palavras (a menos que seja explicação técnica pedida)

3. PREVISIBILIDADE (autismo-friendly):
   - linguagem literal, sem metáfora confusa
   - não invente analogias se não foi pedido
   - estrutura igual entre respostas: validação → 1 ação → frase de fechamento

4. RESPEITAR O QUE FUNCIONA:
   - O usuário tem alto engajamento com TREINO. NÃO motive a treinar mais (já treina).
     Pra treino: dê suporte técnico quando pedir, e só.
   - O usuário tem baixo engajamento com DIETA. AQUI sim você ajuda com:
     - templates de refeição prontos (1 toque mental)
     - estratégias de pre-commitment ("deixe a marmita pronta na noite anterior")
     - reframe de comer junk sem culpa ("comeu um doce, ok. e o próximo é proteína")
   - NUNCA shame food choices. Tudo é dado, não falha.

5. FOCO DO USUÁRIO: definição abdominal. Quando relevante, conecte a sugestão a esse objetivo. Mas NÃO force — se o user perguntar sobre outra coisa, responda a outra coisa.

6. EMOJI OK, mas baixo (1-2 por resposta). Nada de listas com 5 emojis.

${hasNeurodivergence ? `\nNOTA CLÍNICA: o usuário tem ${p.conditions.map(c => ({tdah:'TDAH',tag:'TAG',autismo_possivel:'possível autismo'}[c]||c)).join(' + ')}. Isso explica baixo engajamento com dieta (escape de decisão executiva + ansiedade). NÃO mencione as condições a menos que ele traga. Só ajuste o TOM como descrito acima.` : ''}

CONTEXTO ATUAL DO USUÁRIO:
${aiBuildUserContext()}`;
}

/** Modal de chat livre com a IA. Conversa contínua, history mantida em memória. */
let _aiChatHistory = [];
function modalAIChat() {
  vibrate(10);
  if (!aiReady()) {
    openModal(`
      <div class="p-5 space-y-3">
        <div class="text-center">
          <div class="text-3xl mb-2">🤖</div>
          <h2 class="font-bold text-lg">Conecte Claude</h2>
          <p class="text-xs text-ink/55 dark:text-paper/55 mt-2 leading-relaxed">
            Cole sua API key da Anthropic em <b>Configurações → Claude IA</b>.
            Sem key, eu não consigo conversar.
          </p>
        </div>
        <button class="q-btn q-btn-primary w-full modal-close" onclick="currentTab='config'; render();">→ Ir pra Configurações</button>
        <button class="q-btn q-btn-ghost w-full modal-close text-xs">Fechar</button>
      </div>
    `);
    return;
  }
  openModal(`
    <header class="flex items-center justify-between p-3 border-b border-ink/5 dark:border-paper/5">
      <div class="flex items-center gap-2">
        <span class="text-2xl">🤖</span>
        <div>
          <h2 class="font-bold">Claude</h2>
          <div class="text-[9px] text-ink/45 dark:text-paper/45 uppercase tracking-widest">${state.user.anthropic.model.replace('claude-','').replace(/-2025\d+/, '')}</div>
        </div>
      </div>
      <div class="flex gap-1">
        <button id="ai-clear" class="q-btn q-btn-ghost text-xs px-2 py-1" title="Limpar conversa">↻</button>
        <button class="modal-close p-1" aria-label="Fechar">✕</button>
      </div>
    </header>
    <div id="ai-chat-body" class="p-3 space-y-2 overflow-y-auto" style="max-height:55vh">
      ${_aiChatHistory.length ? _aiChatHistory.map(renderAIMsg).join('') : `
        <div class="text-center text-xs text-ink/55 dark:text-paper/55 italic py-8">
          Pergunte qualquer coisa: dúvida de treino, sugestão de dieta, motivação, técnica…
        </div>
      `}
    </div>
    <form id="ai-form" class="p-3 border-t border-ink/5 dark:border-paper/5 flex gap-2">
      <input id="ai-input" class="q-input flex-1" placeholder="Manda a pergunta…" autocomplete="off" required />
      <button class="q-btn q-btn-primary" type="submit">→</button>
    </form>
  `, { persistent: true });

  const body  = document.getElementById('ai-chat-body');
  const input = document.getElementById('ai-input');
  input.focus();

  document.getElementById('ai-clear').onclick = () => {
    if (!confirm('Limpar conversa?')) return;
    _aiChatHistory = [];
    body.innerHTML = `<div class="text-center text-xs text-ink/55 dark:text-paper/55 italic py-8">Pergunte qualquer coisa…</div>`;
  };

  document.getElementById('ai-form').onsubmit = async (e) => {
    e.preventDefault();
    const userMsg = input.value.trim();
    if (!userMsg) return;
    input.value = '';
    // Append user message
    _aiChatHistory.push({ role: 'user', content: userMsg });
    body.insertAdjacentHTML('beforeend', renderAIMsg({ role: 'user', content: userMsg }));
    // Append typing indicator
    body.insertAdjacentHTML('beforeend', `<div class="ai-msg ai-msg-assistant" id="ai-typing"><span class="ai-typing">▮▮▮</span></div>`);
    body.scrollTop = body.scrollHeight;
    try {
      const reply = await askClaude(aiCoachSystemPrompt(), userMsg, { history: _aiChatHistory.slice(0, -1) });
      document.getElementById('ai-typing')?.remove();
      _aiChatHistory.push({ role: 'assistant', content: reply });
      body.insertAdjacentHTML('beforeend', renderAIMsg({ role: 'assistant', content: reply }));
      body.scrollTop = body.scrollHeight;
    } catch (err) {
      document.getElementById('ai-typing')?.remove();
      body.insertAdjacentHTML('beforeend', `<div class="ai-msg ai-msg-error">Erro: ${err.message}</div>`);
      console.error(err);
    }
  };
}

/** Gera quests personalizadas usando a descrição livre do perfil + Claude.
 *  Salva em state.user.profile.customQuests. Substitui o pool default no
 *  sorteio diário enquanto houver itens. */
async function aiGenerateCustomQuests(opts = {}) {
  if (!aiReady()) throw new Error('IA não configurada');
  const p = state.user.profile || {};
  const description = (p.description || '').trim();
  if (!description) throw new Error('Descreva seu perfil em Config primeiro');
  const system = `Você é especialista em design comportamental e ativação de hábitos.
A partir da descrição de um usuário, GERAR 12 quests diárias PERSONALIZADAS
que serão reforçadoras (prazerosas/interessantes pra ele especificamente).

PRINCÍPIOS:
- Cada quest = 1 ação CONCRETA, mensurável, completável em menos de 30min
- Misturar quests fáceis (1 XP) com médias (2-3 XP) e raras desafiadoras (4 XP)
- Conectar à rotina/gostos descritos — se ele mencionou jogos, criar quests
  com tema de jogos; se mencionou música, com música; etc
- Anti-aversivo: nunca "não faça X", sempre "faça Y"
- Considerar o objetivo principal: ${({definicao_abs:'definição abdominal',massa_geral:'massa muscular',peso_off:'perda de peso',saude:'saúde',performance:'performance'}[p.goal] || 'saúde')}

RESPONDA APENAS JSON VÁLIDO, sem markdown:
{"quests":[{"id":"cq01","text":"...","xp":1,"tag":"..."}, ...]}

Tags válidas: saúde, treino, foco, nutri, sono, mente, lazer, k-pop, criativo
xp: 1 (fácil), 2 (médio), 3 (médio+), 4 (raro)
Texto: max 70 chars, começar com verbo no infinitivo
ids: cq01, cq02, ..., cq12`;
  const reply = await askClaude(system, `DESCRIÇÃO DO USUÁRIO:\n${description}\n\nCONTEXTO:\n${aiBuildUserContext()}`, { maxTokens: 1500 });
  const cleaned = reply.replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(cleaned);
  if (!Array.isArray(parsed.quests) || parsed.quests.length === 0) throw new Error('IA não retornou quests válidas');
  // Sanitiza
  const sanitized = parsed.quests.slice(0, 15).map((q, i) => ({
    id: `cq${String(i+1).padStart(2,'0')}`,
    text: String(q.text || '').slice(0, 100),
    xp: Math.min(4, Math.max(1, +q.xp || 1)),
    tag: String(q.tag || 'lazer').slice(0, 20),
  })).filter(q => q.text);
  state.user.profile.customQuests = sanitized;
  saveState();
  return sanitized;
}

/** Sorteia 1 recompensa não usada hoje da lista personalRewards.
 *  Retorna {text, isNew} ou null se não tem nenhuma cadastrada. */
function pickPersonalReward() {
  const rewards = state.user.personalRewards || [];
  if (!rewards.length) return null;
  const today = todayISO();
  // Filtra os já usados HOJE (anti-spam — não mostra a mesma 2× no mesmo dia)
  const available = rewards.filter((r) => !(r.claimedDates || []).includes(today));
  if (!available.length) return null;
  const r = available[Math.floor(Math.random() * available.length)];
  return { text: r.text, ref: r };
}

/** Mostra modal de recompensa após completar quest/treino/intention. */
function triggerRewardSuggestion(context = 'atividade') {
  const reward = pickPersonalReward();
  if (!reward) return;
  // Probabilidade configurável — 100% por enquanto, fácil de ajustar depois
  const FIRE = 1.0;
  if (Math.random() > FIRE) return;
  openModal(`
    <div class="p-5 text-center space-y-3">
      <div class="text-3xl">🎉</div>
      <div class="text-[10px] uppercase tracking-widest text-ink/45 dark:text-paper/45">você concluiu ${context}</div>
      <div class="text-lg font-bold leading-tight">${reward.text}</div>
      <p class="text-xs text-ink/55 dark:text-paper/55">
        Tá liberado. Faz isso agora se quiser — você ganhou.
      </p>
      <div class="grid grid-cols-2 gap-2 mt-3">
        <button class="q-btn q-btn-ghost text-sm modal-close">Depois</button>
        <button id="claim-reward" class="q-btn q-btn-primary text-sm">✓ Vou aproveitar</button>
      </div>
    </div>
  `);
  document.getElementById('claim-reward').onclick = () => {
    reward.ref.claimedDates = reward.ref.claimedDates || [];
    reward.ref.claimedDates.push(todayISO());
    saveState();
    closeModal();
    toast('Aproveita 😉');
  };
}

